INSERT INTO reviews VALUES(210,'681c52e8293ad62aed5363a9','Worst Experience',replace('Pros :\nCons:','\n',char(10)),3,103,1,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(211,'681c52bc293ad62aed53635d','Worst of the Worst',replace('First, the boss, Hamamoto San. He is one of the most talented BAD person I have ever seen. he terminates employees just because they were talking together.\nSecond, the Head of Engineering Dept, Mirajul. I have no words to explain what kinda bad person he is. But in simple words: arrogant, mannerless, uneducated and many more.\nI have never seen any company worse than Adventure. they treat their employees like slaves. and expect them to work like robots. if you really want to know how bad this company is, simply join there.','\n',char(10)),7,62,1,3,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(212,'681c51d4293ad62aed5361ab','Vung Vang Multiverse','কী সফটওয়্যার বানাবে সেটা নিয়ে কোনো আইডিয়া নাই । কেনো বানাবে সেটাও নিয়ে কোনো আইডিয়া নাই । কেমনে বানাবে এইডা নিয়া একমাত্র আইডিয়া আছে  শুধু এম.ডি.-র (MD) । কিন্তু এম.ডি.-র আবার টেকনোলজি সম্পর্কে কোনো আইডিয়া নাই ! (বিপদ!!! )চারপাশে শুধু VUNG VANG and VUNG VANG ।প্রজেক্ট ম্যানেজাররা একেকজন জোকার। তাদের টেকনোলজি সম্পর্কে তো আইডিয়া নাই আর তেলবাজি তে এক একজন এক একজনের থেকে সেরা। প্রত্যেকদিন এই মেনেজাররা এম.ডি. রে তেল মারে আর ওই তেল এম.ডি. তার নিজের গায়ে সাথে সাথে মাখাইয়া গুইরা বেড়ায় সারা অফিস এ।  মেনেজার রা একটাই কথাই জানে : "হইলো কিছু? আর কতক্ষণ লাগবে?" ডেভেলপার দের সাথে প্রোডাকটিভ কথা ওই ২ টাই। ওই ছাগল রা মনে করে ডেভলপার  ৮ ঘন্টা কোড করবে পারলে খাওয়া দাওয়া, ওয়াসরুম বাদ দিয়ে  । আর প্রজেক্ট ম্যানেজারদের একজন নেতা আছেন যিনি আবার গুটিবাজিতে  উচ্চতর প্রশিক্ষণপ্রাপ্ত।ইন্টারভিউ দিতে গেলে আপনাকে অনেক বড় বড় মূলা দেখাবে । এই মূলা একবার খাইলে শারীরিক এবং মানসিক উভয়ভাবেই আপনি শেষ।',114,37,2,3,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(213,'681c51b6293ad62aed536171','Genieinfo Teach এই কোম্পানিতে কাজ করার মানে হচ্ছে আপনার পেশাদার জীবনের সর্বনাশ ডেকে আনা',replace('Genieinfo Teach এই কোম্পানিতে কাজ করার মানে হচ্ছে আপনার পেশাদার জীবনের সর্বনাশ ডেকে আনা। বাইরে থেকে কোম্পানিটা সফটওয়্যার ফার্ম মনে হলেও, ভেতরে ঢুকলেই বুঝবেন—এটা একেবারে পারিবারিক ব্যবসা!\nকোনো নিয়ম নেই, কোনো পলিসি নেই। কে কখন কী কাজ দেবে, কখন গালমন্দ করবে—সবই পরিবারকেন্দ্রিক মুডের উপর নির্ভর করে। আপনি সকাল 9 টা থেকে রাত ১০টা অবধি কাজ করলেও কেউ কৃতজ্ঞতা প্রকাশ করবে না, বরং আরও চাপ দেবে।\nআর খাওয়ার কথা যদি বলেন—দুপুরে যে লাঞ্চ দেয়, সেটা দেখলে রাস্তায় বসে থাকা ভিখারিও বলে উঠবে, “ভাই আমি তো ভালোই আছি।” খাবারে স্বাদ নেই, পরিমাণ নেই, শুধু লোক দেখানো।\nক্লায়েন্টরা একেকজন আগুন মেজাজের, আর কোম্পানি সেই আগুন আপনার মাথায় ফেলে। যখন কোনো সমস্যা হয়, তখন ম্যানেজমেন্ট চুপ মেরে যায় আর সব দোষ ঠেলে দেয় ডেভেলপারদের ঘাড়ে। ব্যক্তিগত জীবন বলে কিছু থাকবে না—দিন-রাত, ছুটি-শুক্র কিছুই মানে না তারা।\nসরাসরি বললে:Genieinfo Teach একজন পেশাদার ডেভেলপারের জন্য নয়। এটা এমন এক জায়গা, যেখানে আপনার কাজ, সময়, আর সম্মান—তিনটাই ধ্বংস হয়ে যাবে।','\n',char(10)),116,54,1,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(214,'681c51a5293ad62aed536141','ফাকা কলসি বাজে বেশি * গার্মেন্টস ব্যাবসায়ীর বস্তি কোম্পানি',replace('এসএমএস, এসএসএল কমার্স ছাড়া এদের বেচার মত কিছু নাই। নিজের গার্মেন্টস এর ইম্প্রুভমেন্ট এখানকার কামলাদের দিয়ে করায় নেন। এইচআর, সফটওয়্যার সব এখান থেকে। এদিকে ডেভলপার বা আদার টেক টিমের নীড সম্পর্কে কোন আইডিয়া নাই। যে কারণে কেউ নিজে থেকে কোন পুশ দেয়না।\nস্যালারি তো পিয়নের সমান। সি লেভেল আর হেডরা নিজেদের স্যালারি / প্রমোশন নিয়ে বাকিদের ২-৫% দেয়। আর হেডরা সারা বছর বলে যাবেন যে নেক্সট টাউনহোলে দেখতেছি। এটা হচ্ছে সবচেয়ে বড় মুলা।\nলাঞ্চ তো দেয়না বরং ডাইনিং এ বিয়ে বাড়ির মত লাইন করে দাড়ান লাগবে আপনাকে। মাঝে মধ্যে দেখবেন এসি দিয়ে আপনি ঠান্ডা না হলেও আপনি ভিজে যাচ্ছেন পানির ছিটায়। ওয়াসরুমে দেখবেন টিস্যু নেই এক সপ্তাহ থেকে।\nপার্সোনাল থোট: নো ইনক্রিমেন্ট, স্টপ দ্য ওয়ার্ক','\n',char(10)),212,10,1,7,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(215,'681c5125293ad62aed53604e','স্মার্টনেসে ভরপুর, ব্যবস্থাপনায় শূন্য',replace('Pros: লাঞ্চ ফ্যাসিলিটি ভালো, ওভারটাইম করতে হয় না, কলিগরা বেশ ভালো ও হেল্পফুল।\nCons: অপ্রয়োজনীয় শো-অফ অনেক বেশি, তারা ভাবে তাদের কালচার বাংলাদেশের সেরা। আগে ১২ দিন ছুটি ছিল, এখন ২৪ দিন করেছে—যেটা একটা বেসিক দরকার ছিল সবসময়, কিন্তু এটাকে তারা এমনভাবে দেখায় যেন খুব করুণা করছে। কোনো ফ্লেক্সিবিলিটি নেই, মাসের শেষে যদি আপনি মাত্র ১৫ মিনিট কম থাকেন অফিসে, তবুও স্যালারি কাটবে।\nসিনিয়রদের জন্য কাজের পরিবেশ অত্যন্ত খারাপ। আপনি যদি ইঞ্জিনিয়ার হন, তবে গ্রোথের কথা ভুলেই যান—আপনি শুধু CTO-র হাতের পুতুল। এমপ্লয়িদের সামনে অপমান করা যেন নিত্যদিনের ঘটনা। CEO ভাবেন উনি পৃথিবীর সবচেয়ে স্মার্ট মানুষ, একেবারে সবজান্তা শমসের।\nসফটওয়্যার ডেভেলপমেন্ট প্রসেস বলতে কিছুই নেই—CTO যেটা বলবে, সেটাই করতে হবে। একটা কাজ বারবার চেঞ্জ করলে, আপনাকে সেই কাজ বারবার নতুন করে করতেই হবে।\nএই কোম্পানি শুধুমাত্র ফ্রেশার আর ইন্টার্নদের জন্য হতে পারে, অভিজ্ঞদের জন্য একেবারেই না।','\n',char(10)),278,20,1,0,1,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(216,'681c5125293ad62aed53604d','স্যালারি দেয় না ঠিকমত','অফিস দেখতে সুন্দর কিন্তু স্যালারি দেয় না ঠিকমত। স্যালারি নিয়ে ঘুরায়। বাইরে ফিটফাট ভিতরে সদরঘাট। লাস্ট ৩/৪ বছর ধরে ইদের বোনাস ও দেয় না। বাপের অনেক টাকা থাকলে টাইম পাসের জন্য জয়েন করতে পারেন। আমার কথা যাচাই করতে glassdoor এর রিভিউ দেখলেই বুঝতে পারবেন।',91,39,1,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(217,'681c510d293ad62aed536027','Toxic management, toxic environment, never get salary on time',replace('Worked here for three years, left the company for almost 1 year, still did not get my salary cleared, did not get any clearence certificates.\nIn this company there is a culture of insulting people in front of every employee. In some cases for some specific person the management also praise the employee, have to admit that. But the management always try to create pressure over employess to work extra hours. In some cases they will treat you like a garments labour.\nYou will never get your salary on time. it might take to the last date of next month, for example if you are expecting salary for the month of March, it might take you till the last date of  April, in some cases you will not get it. If your salary is over 50k, the avearge paydate starts from next months 24th to the last date. Some of the senior employees did not get salary for 3-4 months. But the management always promise you to give employees this and that, but never fullfill the promise.\nI can recall one event where it was Eid month, the eid day was most probably 17th of the month. almost two third of the employees did not get salary of the previous month, only recieved the bonus, and the managing director went to CANADA for one month tour with his family, without paying the salaries. and the management told us that they have no money to pay.\nIn this company there is no work life balance, no R&D or learning opportunity, will always be overloaded with work, also they will push new works in the existing deadline, and will not increase the deadline.\nAlso the salary structure is not standard.Over all a depressing environment working here.','\n',char(10)),196,87,1,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(218,'681c509d293ad62aed535f66','Genieinfo Teach - এক বিভীষিকাময় অভিজ্ঞতা',replace('Genieinfo Teach - এক বিভীষিকাময় অভিজ্ঞতা\nএই কোম্পানিতে কাজ করাটা আমার ক্যারিয়ারের সবচেয়ে বাজে সিদ্ধান্ত ছিল। এখানে কোনো কাজের সময় নির্ধারিত নেই—দিন হোক বা রাত, হঠাৎ হঠাৎ ম্যাসেজ করে কাজ চাপিয়ে দেওয়া হয়, যেন আপনি কোনো মানুষ না, শুধু একটি কাজের যন্ত্র!\nপরিকল্পনার অভাব, নেতৃত্বের দায়িত্বহীনতা, আর ক্লায়েন্টদের অসহনীয় আচরণ—সব মিলে কাজের পরিবেশ একেবারেই অস্থির। ক্লায়েন্টদের ভুল কিংবা বাজে চাহিদা ডেভেলপারদের ঘাড়ে চাপিয়ে দেওয়া হয়, যেন আমরা সব কিছুর জন্য দায়ী।\nকোনো ধরণের ওয়ার্ক-লাইফ ব্যালেন্স নেই। ছুটি চাইলে খারাপভাবে কথা বলা হয়, আর অফিস টাইম শেষ হলেও কাজ শেষ না হলে আপনাকে যেতে দেওয়া হবে না—অফিস হোক কিংবা রিমোট।\nপ্রথমদিকে ইন্টারনেট বিল বা ছোটখাটো সুবিধা দিয়ে প্রলুব্ধ করা হয়, কিন্তু পরে সেই সুবিধার গুরুত্ব একেবারে ফিকে হয়ে যায় অতিরিক্ত চাপ আর অসম্মানের ভেতরে।\nএই প্রতিষ্ঠানে কারো যোগ দেওয়ার আগে অনুরোধ থাকবে—ভালোভাবে চিন্তা করুন। আপনার মানসিক স্বাস্থ্য, পরিবার, ও ক্যারিয়ার—সবই ক্ষতিগ্রস্ত হতে পারে।','\n',char(10)),116,4,2,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(219,'681c4fc0293ad62aed535dd2','Overall very good',replace('pros:1) Almost everything is top notch\n2) cons:yearly increment is very poor. this is the only one problem here.','\n',char(10)),258,75,2,6,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(220,'681c4fb6293ad62aed535dbc','Destroyed the scope of my career growth',replace('I was selected after multiple interviews (3 technical). I was told that I will be working on Spring boot. I was even asked if i will be able to do projects in their existing Spring boot project. I never knew that it was a lie until the first day of my job there. The team where I was assigned to had a awesome team lead. But, team lead assigned me to people who practically lacked the expertise of training interns. I whole codebase was about 1 gb (just imagine the size of the codebase). I just worked on some mvc projects at my university. And, I was there assigned to work on this legacy codebase which lacked proper coding practices. Also, eight people were working on the project didn''t have idea of who was working on what. Two people knew about database more, whereas others knew about something else. It''s like as an intern I was expected to learn\neverything within a month. I literally was in a shock. It took 5 minutes - 10 minutes to load the entire project first time. And regularly it took 4 minutes. It had so many error logs. Yet none cared. Groovy on grails project is also backdated lacks proper documentation. Whenever i asked them to tell me how it worked, they werent that interested. One of their senior engineer literally doesnt code even though he knows business logic. They lacked passion and the need to write good code. I felt like I was cheated. These people werent engineers. They were developers at best. I was trying to know about how their codebase works. Oneday I faced an issue and asked a senior bhai for help. He said to me literally "Boloder moto kotha bolen ken. Amra nijerai oneke janina eshob. Eshob ghatte jan ken". I was shocked by his unprofessionalism.\nTheir HR did nothing to redeem my situation. They seemed so helpful. I asked them to transfer me to a new team at the last moment. They told me that they will notify me. But, they didn''t do anything. After 3 months I gave up hope. I left that place with tears. This was my first job. I will never forgive BRAC IT for ruining my first job.\nApart from the team lead and two other engineers, rest others are either unprofessional, unsupportive and all of them lacks passion.','\n',char(10)),34,8,1,5,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(221,'681c4f63293ad62aed535d28','Shorbange betha, oushodh dibo kotha',replace('Probation Period Mismanagement\nOfficial probation period is 3 months, but some employees are still not confirmed even after 8 months.\nUnclear & Changing Bonus Policy\nEid bonus was promised after 3 months.\nLater changed to 6 months.\nNow the requirement is 12 months — all without formal notice or policy update.\nUnfair Increment Structure\nIncrement after 1 year is only 1,000–3,000 BDT.\nEven the best performers receive only 3,000 BDT.\nSome employees receive no increment despite meeting KPIs.\nLeave Application Rejections Without Reason\nLeave requests are often denied without any explanation.\nSalary deductions occur if leave is not accepted, regardless of employee compliance.\nStrict and Unreasonable Leave Policy\nMust apply 3 days in advance for even 1 casual leave.\nEmergency leaves involve excessive hurdles.\nExcessive Workload\nEmployees are required to work 6 days a week, with no flexible options.\nUnethical Resignation Handling\nEmployees resigning formally are not paid final salaries on time.\nNOCs are delayed or denied.\nHR and management provide no cooperation during the exit process.','\n',char(10)),118,115,1,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(222,'681c4f45293ad62aed535cf7','A Great Place to Grow and Innovate','Working at AppifyDevs has been a rewarding and inspiring journey. The company fosters a supportive and collaborative environment, and the CEO  is incredibly friendly and always willing to help. Learning is continuous, and innovation is genuinely encouraged. As a developer, I’ve had the opportunity to work on diverse and challenging projects using modern technologies',16,105,2,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(223,'681c4e6c293ad62aed535c29','A Life Trapped in the Hope of Salary',replace('আমিআলফা সফট টেকনোলজিনামে একটি কোম্পানিতে ২০২৪ সালের ১ অক্টোবর যোগদান করেছিলাম। যোগদানের পর থেকেই আমি সততার সঙ্গে কাজ করতে থাকি। কিন্তু এক মাস যাওয়ার পর ১০ দিন চলে গেল, তখনো বেতন পেলাম না। বেতন নিয়ে খোঁজখবর নিয়ে জানতে পারলাম, এর আগের দুই মাস ধরেও বেতন দেওয়া হয়নি। তারপর "এই সপ্তাহ", "সেই সপ্তাহ" করে তিন মাস চলে গেল। এর মধ্যে কোম্পানির এমডি''র জন্মদিন উদযাপন হলো, যেখানে লক্ষ লক্ষ টাকা খরচ করা হলো, মদ খাওয়া হলো। এছাড়াও প্রায়ই কোম্পানির এমডি এবং উর্ধ্বতন কর্মকর্তারা অফিসে বসে পার্টি করতেন এবং বিদেশি মদ খেতেন। নিউ ইয়ার উপলক্ষে পিকনিক করলেন, সব কিছুই করলেন, কিন্তু আমাদের বেতন দিলেন না।\nআর সহ্য করতে না পেরে আমি চাকরিটি ছেড়ে দিলাম। তারপরও গত পাঁচ মাস ধরে বারবার তারিখ দেওয়া হলো, কিন্তু টাকা দেওয়া হলো না। এর মধ্যে আমরা যারা এমপ্লয়ি ছিলাম, তারা নিজেদের পরিবার এবং সমাজে মান-সম্মান হারিয়ে ফেলেছি।\nতারপর ৪ মে আমাদের আবার ডাকা হলো। আমরা সকাল ১০টায় গিয়ে উপস্থিত হলাম। তিনি বললেন চেক দেবেন, কিন্তু তিনি এলেন বিকাল ৫টায়। এসে আমাদের চেক না দিয়ে এনডিএ (NDA) সাইন করতে বললেন। আমরা জানালাম, আমাদের প্রাপ্য টাকা না পেলে আমরা এনডিএ সাইন করব না। তখন তিনি তার ভাড়া করা গুণ্ডাদের দিয়ে আমাদের মারতে আসেন এবং প্রাণনাশের হুমকি দেন ও অকথ্য ভাষায় গালিগালাজ করেন।\nI joined a company namedAlpha Soft Technology Ltd.on October 1, 2024. From the very beginning, I worked with honesty. However, after a month passed, 10 more days went by and I still didn’t receive my salary. Upon inquiring, I learned that salaries hadn’t been paid for the previous two months either. Then it kept being postponed with excuses like “this week” or “next week,” and three months went by.\nDuring this time, the company’s MD celebrated his birthday by spending hundreds of thousands of taka, drinking alcohol. Moreover, the MD and senior executives would frequently hold parties in the office and consume imported liquor. They organized a New Year picnic and everything else, but still didn’t pay us our salaries.\nUnable to tolerate the situation anymore, I resigned. Even after that, for the next five months, they kept giving us dates but never paid. During this time, those of us who were employees lost our dignity in front of our families and in society.\nThen, on May 4, we were called again. We went at 10 in the morning. He said he would give us checks, but he arrived at 5 in the evening. Instead of giving us checks, he asked us to sign an NDA. We made it clear that we wouldn’t sign any NDA without receiving our due salaries. At that point, he sent his hired thugs to attack us, issued death threats, and hurled abusive language at us.','\n',char(10)),12,12,1,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(224,'681c4dc4293ad62aed535b41','Looks Like a Company, Feels Like a Trap | Not a Workplace — Just a Well-Packaged Disaster',replace('A Family-Owned Disaster Masquerading as a Tech Company1. A Family Drama, Not a CompanyThis place is run entirely by one family — the MD, CEO, CTO, HR, CFO you name it. If you’re not related, you’re just another disposable worker. They micromanage everything, expect you to work during holidays and from home, and act like they own your time and your life.\n2. Salary? Delayed, Cut, or "Pending" ForeverForget regular payments. You’ll get your salary in pieces, whenever they "have funds" — which somehow never aligns with payday. Even with a raise, they’ll hold back the extra. People wait months, year or more to get what they''re owed, while leadership burns cash on personal projects and politics.\n3. No Growth, No Respect, No Fair PayEveryone’s underpaid — juniors, seniors, doesn’t matter. Seniors are treated like a liability, often pushed out to save costs. There’s no path for learning or promotion, just a stagnant system run by long-time family hires playing boss with zero real skills.\n4. Total Chaos, No ManagementNo planning, no task tracking, no real leadership. Work is assigned on whims. One day you''re appreciated, the next you''re accused of slacking with no reason. Even if you show proof, they won’t care. It’s all disorganized, reactive, and toxic.\n5. HR & Admin = Power-Tripping MessHR (Tanbeer) and Admin (Tanvir) are the worst part — rude, unprofessional, and completely unaccountable. There are no real policies, just whatever they feel like enforcing that day. They’ll twist rules, play favorites, and act like they’re above accountability. Forget support — theyarethe problem.Bonus: Run Now, Regret Later — Trust Me','\n',char(10)),88,48,1,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(225,'681c4d2e293ad62aed535a32','Unprofessional and Mismanaged',replace('RapidSmartERP কোম্পানি সম্পর্কে আমার অভিজ্ঞতা\nআমি RapidSmartERP কোম্পানিতে কাজ করার অভিজ্ঞতার ভিত্তিতে কিছু গুরুত্বপূর্ণ বিষয় তুলে ধরতে চাই, যা ভবিষ্যতে যারা এখানে কাজ করার কথা ভাবছেন তাদের জন্য সহায়ক হতে পারে।\n১. পরিচালনার অভাব:এই কোম্পানিতে কোনো প্রকার প্রাতিষ্ঠানিক ম্যানেজমেন্ট স্ট্রাকচার নেই। সকল কিছু – কাজ দেওয়া, কাজ গ্রহণ, এমনকি বেতন প্রদানের মতো গুরুত্বপূর্ণ বিষয় – একটি মাত্র ব্যক্তি (জাহাঙ্গীর নামক) পরিচালনা করেন। এতে কাজের স্বচ্ছতা এবং দায়বদ্ধতার অভাব থাকে।\n২. চাকরির অফার লেটার না দেওয়া:চাকরিতে নির্বাচিত হওয়ার পরও কোনো অফার লেটার প্রদান করা হয় না, যা খুবই অপেশাদার আচরণ। এটি ভবিষ্যতে চাকরি সংক্রান্ত কোনো সমস্যা হলে প্রমাণ বা রেফারেন্সের অভাব ঘটায়।\n৩. বেতন নিয়ে প্রতারণা:আপনাকে কাজ দেওয়া হবে এবং আপনি সেটি সম্পন্ন করে রিপোর্ট করবেন, কিন্তু যখন বেতন দেওয়ার সময় আসবে তখন বলা হবে আপনার কাজ অগ্রহণযোগ্য, অর্থহীন বা তাদের প্রয়োজন অনুযায়ী নয়। এসব অজুহাতে বেতন আটকে রাখা হয়।\n৪. পরিষ্কার নির্দেশনা না দেওয়া:অনেক সময় কাজ করার পর বলা হয়, "এটা আমার রিকোয়ারমেন্ট না", অথচ আগে সে বিষয়ে কোনো স্পষ্ট নির্দেশনা দেয়া হয়নি। এতে কর্মীর সময় ও শ্রম অপচয় হয় এবং তবুও বেতন থেকে বঞ্চিত হতে হয়।\n৫. এইচআর-এর অপেশাদার আচরণ:এই কোম্পানির HR টিম অত্যন্ত রূঢ় এবং অসৌজন্যমূলক আচরণ করে। পেশাগত ভদ্রতা ও মানবিক আচরণের অভাব রয়েছে।\n৬. অত্যধিক কর্মঘণ্টা ও ছুটি না দেওয়া:প্রতিদিন দীর্ঘ সময় কাজ করতে হয় এবং সপ্তাহে ৬ দিন অফিস করতে হয়। কোনো প্রকার পেইড লিভ (বেতনসহ ছুটি) দেয়া হয় না। ছুটি নিলে সরাসরি বেতন কেটে নেওয়া হয়।\n৭. দলবদ্ধ কাজের পরিবেশ নেই:কাজের জন্য কোনো টিম নেই, সবাই নিজে নিজে কাজ করতে বাধ্য। এতে শেখার সুযোগ কম থাকে এবং সহযোগিতামূলক পরিবেশ তৈরি হয় না।\n৮. পেশাগত উন্নয়নের সুযোগ নেই:এখানে বেশিরভাগ কাজই একঘেয়ে এবং কোনো ধরনের স্কিল ডেভেলপমেন্ট বা ক্যারিয়ার গ্রোথের সুযোগ নেই। নতুন কিছু শেখার বা উন্নতি করার পরিবেশও অনুপস্থিত।\n৯. বেতনের স্বচ্ছতা নেই:বেতন কখন দেয়া হবে, কত দেয়া হবে – এ নিয়ে কোনো পরিষ্কার ধারণা দেয়া হয় না। প্রায়শই বেতন বিলম্বিত হয় এবং কৃতজ্ঞতা বা জবাবদিহিতার অভাব দেখা যায়।\n---\nএই অভিজ্ঞতা আমি শেয়ার করলাম যাতে ভবিষ্যতে অন্য কেউ এমন পরিবেশে না পড়ে বা অন্তত সচেতন থাকে। পেশাদার পরিবেশে কাজ করতে চাইলে RapidSmartERP সম্ভবত সঠিক জায়গা নয়।','\n',char(10)),202,79,1,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(226,'681c4c67293ad62aed5358ba','প্রতারক কোম্পানি',replace('জবে জয়েন করার পর থেকেই শুনছি, অনেকের বেতন ৭-৮ মাস যাবত হচ্ছে না। দিব দিব করে আমার ও ৫ মাসের বেতন বাকি। হাতে টাকা নাই, এই সমস্যা ওই সমস্যা বলে অনেক কর্মীর থেকে  টাকা ধার নিছে। কালকেই দিয়ে দিব বলে সেই কাল আর আসে নাই। কোম্পানির এম ডি আরিফুল ইসলাম টিটু  সে সবার সামনে খুব ভালো সাজার চেস্টা করলেও সে স্বার্থের জন্য যেকোনো সময় প্রতারনা করতে প্রস্তুত। যারা ওই কোম্পানিতে জয়েন করছে কেওই সম্পূর্ণ টাকা পেয়ে বের হতে পারেনি, বরং অনেক টাকা বাকি রেখে নিরবে কাদতে কাদতে বের হতে হয়েছে। কোম্পানির চেয়ারম্যান সোনালি ব্যাঙ্কের প্রিন্সিপাল অফিসার রফিকুল ইসলাম একজন জুয়ারু, মদখোর। অফিসে বসে প্রায়ই ড্রিংক্স করে আর কর্মীদের সাথে খারাপ অকথ্য ভাষায় গালিগালাজ করে।\nতারা কর্মীদের বেতন না দিয়ে মাসের পর মাস কাজ করিয়ে বাধ্য করে রিজাইন দিয়ে খালি হাতে চলে যেতে। অথচ এই টিটু হাতে টাকা পেলেই দেশের বাইরে গিয়ে জুয়া খেলে টাকা খরচ করে আসে। অথচ অনেকেই তার সামনে কান্না করছে টাকার জন্য তাও সে কাল দিব বলে প্রতারনা করেই গেছে।','\n',char(10)),12,92,1,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(227,'681c4bf0293ad62aed5357dc','Bad working place for Designer','They have a strong design team, but they don''t know how to utilise this properly. CEO and other team members are very generous. But if you’re going to work with Nijam your life is going to be hell. He is a very abusive person and he dont care about what you feel. He will insult in your every word and make you feel like you’re a trash even if I''m a woman. If you complain this to the management they will not take any action, if you want to leave job for this reason you’re free to go. They only care about this nijam guy. Also misbehave and insulting publicly is very normal in this company. I might did not face the bad behaviour of others, but while working in the same room I saw the other team leader also behave very badly.',279,27,1,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(228,'681c4bc8293ad62aed53578b','Genieinfo Teach ডেভেলপারদের প্রতি প্রয়োজনীয় সম্মান ও মূল্যায়ন দেখায় না।',replace('আমি Genieinfo Teach-এ কাজ করার অভিজ্ঞতা খুবই হতাশাজনক পেয়েছি। কোম্পানিটি ডেভেলপারদের প্রতি প্রয়োজনীয় সম্মান ও মূল্যায়ন দেখায় না। অফিস টাইমের বাইরে অতিরিক্ত কাজ করানো হয়, কিন্তু সেই পরিশ্রমের সঠিক মূল্য দেওয়া হয় না।\nপ্রজেক্টে কোনো সমস্যা হলে সেটা নিজেদের দায়িত্ব না নিয়ে ডেভেলপারদের ঘাড়ে চাপিয়ে দেওয়া হয়। এমনকি কখনও কখনও অপেশাদার ব্যবহারের সম্মুখীন হতে হয়, যা একেবারেই অগ্রহণযোগ্য।\nসব মিলিয়ে একজন প্রযুক্তিপেশাদার হিসেবে এই প্রতিষ্ঠানে কাজ করা আমার জন্য অত্যন্ত হতাশাজনক অভিজ্ঞতা ছিল।\nআমি নতুন ডেভেলপারদের সতর্ক থাকতে এবং ভালভাবে যাচাই-বাছাই করে তবেই সিদ্ধান্ত নেওয়ার অনুরোধ করছি।','\n',char(10)),117,55,1,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(229,'681c4bb9293ad62aed53576d','Exceptional Development Partner!','Working with AppifyDevs has been an outstanding experience. Their team is professional, highly skilled, and truly committed to delivering quality work on time. From clear communication to expert-level problem solving, they exceeded expectations at every stage of our project. Whether it''s frontend, backend, or full-stack development, AppifyDevs stands out as a reliable and innovative tech partner. Highly recommended for anyone looking to build scalable and modern digital solutions!',18,42,2,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(230,'681c4b29293ad62aed535650','Worst Company ever also with worst management',replace('1. The management is totally crap. PM AKM Golam Murshed is very bad person. He doesn''t give proper increment to employee and just force employee to work at overtime.\n2. Backend team lead Plabon ghosh is very sly person. He supports whoever just oiling him like zahid hasan. He does not think twice to cut an employee off.\n****Be careful joining in dev team.','\n',char(10)),71,104,2,1,1,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(231,'681c4b03293ad62aed5355f0','Good Team Culture and Flexible Work Environment',replace('I''ve been working here for a while now, and it''s been a great experience. The work environment is relaxed and supportive—there''s no time tracking, which shows the trust they place in their team. The CEO is incredibly friendly and always willing to help. It''s a startup with a small team for now, but the CEO has a strong vision and a solid background in DevOps, along with proficiency in multiple programming languages. That makes collaboration much smoother—you don’t need to over-explain things.\nThe team culture is one of mutual support. No one cares about who works how many hours; we just help each other whenever needed. If you''re looking for a place to grow or want to commit long-term, this could be a great opportunity.','\n',char(10)),16,81,3,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(232,'681c4a7e293ad62aed5354f5','One of a kind company in Bangladesh','',167,62,2,5,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(233,'681c4996293ad62aed53535c','বেস্ট ফর গ্রোথ, কালচার, ইঞ্জিনিয়ারিং',replace('সুবিধা:\n১. সুপার ফ্লেক্সিবল।অফিসে যখন ইচ্ছা বের হতে পারবেন, যখন ইচ্ছা ঢুকতে পারবেন।কিন্তু নিজের কাজ ঠিকমত করতে হবে।\n২.ফ্রি লাঞ্চ, স্ন্যাক্স\n৩.সবাই বেশ সাপোর্টিভ\n৪.কোম্পানির লিডার রা জিনিয়িয়াস ইঞ্জিনিয়ার এবং জেন্টেলম্যান।ম্যানেজমেন্ট অনেক ভালো\n৫.ইয়ারলি ট্যুর, টিম ডিনার\n৬.রেগুলার ট্রেইনিং সেশন,প্রফেশনাল সার্টিফিকেশন ফি সাপোর্ট\n৭.অনেক এক্সপেরিয়েন্সড ইঞ্জিনিয়ার কাজ করে এখানে।লার্নিং অপরচুনিটি অনেক\n৮.স্যালারি অলওয়েজ অনটাইম।প্রতি মাসের বেতন আগের মাসেই ২৮/২৯ তারিখে দিয়ে দেয়।\n৯.লো পারফরমেন্স হলে অনেক দিন সময় দেয়া হয় পারফরমেন্স ঠিক করার জন্য।\n১০.ভেরি গুড স্যালারি রেঞ্জ\n১১.ফায়ার করে দিলেও এডভান্স দুই মাসের স্যালারি দিয়ে দেয়া হয়\nকিছু অসুবিধা:\n১.মাঝে মাঝে প্রজেক্ট থাকে না।কিছু দিন বসে থাকতে হয়।\n২.সবসময় পছন্দমত প্রজেক্ট নাও পরতে পারে।যেহেতু সার্ভিস বেসড কোম্পানি।\n৩.কিছু প্রজেক্টে ওয়ার্ক প্রেশার বেশি থাকে মাঝে মাঝে।ওয়ার্ক লাইফ ব্যালেন্স করা সম্ভব হয় না তখন','\n',char(10)),95,94,3,2,8,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(234,'681c4959293ad62aed5352eb','তেলবাজী করতে পারলে আপনি আছেন নাইলে নাই!',replace('💥 প্রতারণার সীমা ছাড়ানো একটা কোম্পানি – LoveUmrah.com 💥\n👉মালিক সাহেব লন্ডন প্রবাসী, নাম মুজিরুল হক। কিন্তু দেশে বসে নাটক চালান আর অফিস চালান কিছু ''বিশেষ'' লোক দিয়ে।নিকুঞ্জে একটা ছোট অফিস ভাড়া নিয়ে রেখেছে, কিন্তু ওখানে যা হয় তা কাজ না — একদম নাটক!\n👩‍💼ম্যানেজার নামের এক ভাবনগরী বসে আছেন — ভাব এত বেশি যে মুখের দিকে তাকালে মাথা ধরে যায়!এই মহিলা এমডির সবচেয়ে প্রিয় — এমডি দেশে না থাকলে তার রুমে বসেন, আর এমডি দেশে থাকলে একই রুমে বসেন — বুঝতেই পারছেন কী চলছে! মাসে মাসে লন্ডন ট্রিপ, হ্যাঁ, এমডির খরচে! আর সাধারণ কর্মচারী? তাদের স্যালারির টাকাই খাওয়া পড়ে!\n🚬অফিসের পরিবেশ এত বাজে, যে রেস্ট রুমটাই স্মোকিং জোন। গন্ধে টিকে থাকা যায় না!কে কবে কী কাজ করছে কারো হদিস নাই, ম্যানেজার আর তার ক্লাবের লোকজন রঙ্গমঞ্চ চালায়!\n💸এবার আসল নাটক – স্যালারি!\nবলা হয় ১৫-২০ তারিখের মধ্যে স্যালারি দিবে — হাস্যকর কথা! ২৫ পেরিয়ে যায়, তাও টাকাই আসে না।\nকেউ যদি চাকরি ছাড়ে বা তাকে বাদ দেয়, তখন শুরু হয় মূল খেলা — এক মাসের দেয়, বাকি দুই মাসের আটকে রাখে।\nআর বাদ দেওয়ার স্টাইল? কোনো নোটিশ নাই, হুট করে একদিন একটা মেইল – “আপনি নাই।”\n📢এই পোস্ট লিখছি কারণ এই কোম্পানির জন্য অনেক ছেলে-মেয়ে ঠকছে, মানসিকভাবে ভেঙে পড়ছে। তাই বলে দিচ্ছি — এই LoveUmrah একটা ধোঁকাবাজ প্রতিষ্ঠানের নাম।\n🛑 চাকরি খুঁজছেন? এই অফিসে ঢোকার আগে দু’বার ভাববেন।🛑 ভিজিটর বা কাস্টমার? সাবধান! যারা নিজেদের স্টাফের সাথেই এভাবে আচরণ করে, তারা কাস্টমারকে কীভাবে ট্রিট করে, সেটা সহজেই বোঝা যায়।','\n',char(10)),38,59,1,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(235,'681c47eb293ad62aed53504c','Management with Zero Technical Knowledge Leading IT Teams',replace('I don’t understand how someone who graduated from accounting or marketing can become the team leader of an IT team. Yet, almost every IT team has this kind of leadership. They have zero understanding of coding, engineering, or how software actually works—but they’ll keep shouting at you to “finish it today.”\nThe senior developer writes garbage code and always blames others for any issues. Somehow, by flattering the boss and MD, they get promoted every year.\nOffice hours are from 9:30 AM to 6:00 PM, but if you try to leave at 6, the team leader will give you a dirty look and ask, “How can you leave at 6? Don’t you have work?”\nThere isno career growth—I repeat,no career growth.\nThere’s not even a proper tester in the company. The marketing team claims they are the testers.','\n',char(10)),114,27,2,6,1,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(236,'681c46d3293ad62aed534e1a','ব্র্যাক আইটি - উপরে ফিটফাট ভিতরে সদরঘাট',replace('নতুন অফিস নিয়া এখন লোকজনের বেতন দিতে পারেনা। খালি শো অফ! মিনহাজের মত একজন শিক্ষিত লোক থাকলে আপনি শুধু চাকর হিসেবে থাকতে পারবেন।\nদেশ থেকে এক স্বৈরাচার বিদায় করেছি কিন্তু ইন্ডাস্ট্রি থেকে এরকম স্বৈরাচার দুর করতে পারবেননা যতদিন সিও এর মত হাবা লোক থাকবে। তপু ভাইয়ের মত একজন ট্যালেন্টেড মানুষকে এত হেয় করে কথা বলার যোগ্যতা নাই। বেচারা','\n',char(10)),34,48,1,3,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(237,'681c45f8293ad62aed534c4a','Scamming company | Black money convert to white money','I''ve been working at a company for about a year. The company operates like a multi-level marketing (MLM) business, but it seems like a lot of the money they make comes from shady practices. They collect money from government officers and secretaries, and it looks like they have ways to clean that money and make it look legitimate. as like black money white.',173,91,1,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(238,'681c45cd293ad62aed534be9','An intensively Toxic Management with 0 technical Knowledge',replace('Pros\n* Timely salary * Flexible office environment (They don''t care what are you doing in free time)\nCons\n* Non-Technical Project Managers: The project managers are making developers'' lives difficult. They don''t understand technical issues and just agree with the MD, even if the task is impossible. Developers have to personally explain the situation to the MD, which adds unnecessary stress. * Unprofessional Behavior: The project managers expect you to stay past 6 PM, even though the official office hours are 9:30 to 6. Leaving on time gets you disapproving looks from them and the MD. * Unrealistic KPIs: The MD values noise and aggression over actual work. Shouting and causing a scene are seen as productive, while quietly doing your job is not appreciated. Poor Salary Review Process: The MD prioritizes another business, Shadhin Music, and rewards those who flatter him. At Gakk, project managers get good raises for pressuring developers, making them seem heroic. * Inappropriate Calls: The project managers often call the wrong developers for issues, even late at night or when you''re hospitalized. They don''t understand which problems are relevant to which roles. * Lack of Code Quality: There''s no emphasis on good coding practices. It''s not a great place for junior developers, but mid/senior developers can navigate it. The turnover is high, with no good developers staying more than 1.5 years unless they have personal issues. * No Employee Benefits: There are no lunch, transport, or health benefits. The company provides no support beyond salary, and developers struggle with lunch unless they bring food from home. * No QA Team: There is no dedicated Quality Assurance team, leading to many preventable issues and bugs in the final products. * Difficult to Take Leave: Taking leave is challenging as the management thinks giving two off days a week is generous enough. Additional leave requests are often met with resistance. * No Work From Home: There is no option for working from home. During the COVID crisis, the MD required employees to come to the office, disregarding health and safety concerns.\nAdvice to Management\nNothing to say. The MD or higher authority will never even check glassdoor. Developers just be careful before join. And negotiate. Hit for the biggest number at first place. Otherwise you''ll be dragged behind forever.','\n',char(10)),114,69,1,6,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(239,'681c4571293ad62aed534b30','Run, No less than a garments factory, No growth, just lame showoffs','No less than a garments factory. A company with religious show-offs. They don’t have a proper structure; they work in a communist style. No matter if you have 1 year of experience or 6–7 years, you’ll get the same designation. Even people with more experience are treated badly. They’re more comfortable working with interns. No flexibility—just rules and regulations. The CTO and CEO behave like a one-man army. They don’t care about what others think. If you’re working on a product, you don’t have any floor to talk. You’ll just do whatever you’re told to. A very bad workplace for software professionals.',278,115,1,2,1,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(240,'681c4569293ad62aed534b24','BRAC IT তে জয়েন করবেন তো ক্যারিয়ার শেষ',replace('Zero career growth\nEven Engineers have to do slavery to Minhaj\nLess qualified seniors\nWorst CEO and CTO\n2 CTOs but one is actual boss','\n',char(10)),35,82,1,4,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(241,'681c4444293ad62aed534943','Salary Problem','Lat Month er SAlary dei na. One Man Army, 2 Bhai e company chalai ekjon deshe arek jon bidese. chatukar duijon ase onek din dore sobai chole jai oi duita ajo roye jai. ami chilam kichu din obosta khuboi baje',27,118,1,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(242,'681c43e3293ad62aed5348ab','Good & Ethical Company',replace('I used to work there. Not alrounder, but CEO have great visions.Tight about timing. No extra work but work under pressure. Always pushing harder like all struggling company does.\nThe great thing is Salary on-time, fixed working hour, breakfast & lunch from the office. Islamic vibe is maintained. But workload is heavy.\neito... motamoti sob dik theke valoi, jodi keu pressure niye kaj shikhte chai, tahole shekhar sujog onek beshi. R jara relax thakte chan, tader jonno ei company na.','\n',char(10)),76,27,3,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(243,'681c4323293ad62aed5347a5','Beware: No Learning, No Security, Only Oiling the Boss',replace('- The MD has bad history about female employee and the work hour is not suitable for women.\n- Environment is toxic, and everybody is busy to oiling the boss.\n- No work life balance, people start office at 11 AM and work till night. As long you stay at office as good you are to management they call it dedication. and they care dedication over skills.\n- No way to learn or work in Modern Software Engineering coz they hunt project from upwork or freelancer and they have no control over it to take any decision on it.\n- Clients is God and the Management will charge you if the client gone away (even it''s not your fault).\n- You have to work under a supreme leader and you cannot use your own face in git commit. So all the work you done there will be one single person face and name.\n- There is no Sr Engineer, if you check employees in linkedin you will see the employees has average 2 years of experience, so when you join it''s all about yourself.\n- By the time you resign, they will cast you as poison and send you to home office. Also there is higher chance to not get any bonus or even worse to not get the salary.\n- I can see some of the JR Dev wrote that they have health insurance and retirement plans which is a big lie, before you join ask them to show any legal document on it, i beat they can''t.\nIt''s a big no if you are a Mid level or sr engineer , There is no job security.\nBefore you joining the toxic office pick some ex-employees in linkedin to verify the work environment and learning scope.\nBefore you join, Ask to show any legal document about health insurance and retirement plans if they mention any of it in job description or in interview board. It''s important to see it coz the boss is big liar.','\n',char(10)),159,76,1,4,1,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(244,'681c42f9293ad62aed53476f','দেশি খাঁটি পঁচা মূলা','এই মূলা একবার খাইলে শারীরিক এবং মানসিক উভয়ভাবেই আপনি শেষ।',48,17,1,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(245,'681c429e293ad62aed5346e8','কর্পোরেট কালচার ও হাই প্রেশার সিচুয়েশনে কাজ শিখার জন্য বেস্ট প্লেস।',replace('জায়গাটা একদিক থেকে ভালো—কর্পোরেট কালচার, অফিস পলিটিক্স, প্রেশার হ্যান্ডেলিং শেখার জন্য কাজে দেয়। এখানে কাজের চাপ অনেক বেশি, আমরা তো মাঝে মাঝে রাত ২টা পর্যন্তও অফিস করেছি। ডেডলাইন খুব টাইট থাকে।\nএমডি আসলে মানুষটা ভালো, এমপ্লয়িদের কেয়ার করে। তবে কোম্পানি গ্রুপের মধ্যে হওয়ায় কিছু পলিটিক্স, নেপটিজম এসব থাকেই। সিটিও খুব বেশি হ্যান্ডস-অন না, প্র‍্যাকটিকাল সাপোর্ট কম, বেশি থিওরি বলে।\nছুটি পাওয়া কঠিন, স্যালারি দিতেও কিছুটা দেরি হয় প্রায়ই। বেসিক ফ্যাসিলিটিজও সীমিত—ওয়ার্কস্টেশন, বেনিফিটস, এইগুলোতে ঘাটতি আছে। যদি বড় কর্পোরেট বা চ্যালেঞ্জিং এনভায়রনমেন্টে যাওয়ার প্ল্যান থাকে, তাহলে এখানে কিছুদিন কাজ করলে ওই প্রেশার, পলিটিক্স, নেটওয়ার্কিং এগুলো শিখে নেওয়া যাবে। কিন্তু লং টার্মের জন্য না। ক্যারিয়ারের শুরুর দিকে এক্সপেরিয়েন্স গেইনের জন্য ঠিক আছে, পরে অবশ্যই আরও ভালো অপশন খুঁজতে হবে।','\n',char(10)),173,69,3,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(246,'681c426c293ad62aed534693','"ম্যানেজমেন্ট এতটাই এক্সেসিবল এবং বন্ধুত্বপূর্ণ যে যেকোনো সমস্যা বা আইডিয়া নিয়ে সরাসরি আলোচনা করা যায়।"','"PROMITI-এ কাজ করার অভিজ্ঞতা সত্যিই দারুণ — এখানে অফিসের পরিবেশ শান্ত ও বন্ধুত্বপূর্ণ, সহকর্মীরা সবসময় সহায়ক, আর ম্যানেজমেন্ট এতটাই সহযোগিতাপরায়ণ যে যেকোনো বিষয়েই খোলামেলা আলোচনা করা যায় এবং প্রয়োজনীয় সাপোর্টও সহজেই পাওয়া যায়।"',199,70,3,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(247,'681c4243293ad62aed534656','Management appears disconnected from the needs and well-being of their engineering team',replace('While the general employees at DSI are friendly and cooperative, the overall environment is plagued by management bias. Employees are heavily favored by leadership, not based on their work ethic or results, but on how much attention they attract or how well they align with management''s directives.\nTeam leads and engineering managers appear to care more about pleasing upper management than supporting their own teams. Work-life balance is poor  requests for work-from-home are denied, and even casual leave is treated as a privilege rather than a right. In some cases, casual leaves are rejected without proper reasoning.\nThere is also a concerning culture where disagreeing with management can lead to rude or disrespectful behavior from team leads. Employee are fourced to work with leagcy technologies. Talented engineers are being let go, while non-technical individuals some with no knowledge of the software industry are being hired. Favoritism is clear: if you''re close to the CTO, your job is safe and you''ll receive raises. But if you''re working hard behind the scenes and not on their radar, you risk being labeled a low performer.\nThe so called "transformations" initiated by management are worsening the situation rather than improving it. Engineer morale and satisfaction are decreasing day by day. DSI needs serious internal reform if it wants to retain skilled and motivated talent.','\n',char(10)),82,59,1,9,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(248,'681c411c293ad62aed5344a1','Toxic Work Environment: A Company Plagued by Mismanagement, Zero Employee Benefits, and Arbitrary Terminations',replace('Pros\n1. Offers good opportunities for freshers to kick-start their careers.2. Management accommodates academic needs, provides support during exams, and deals with other important matters.\nCons\nThe company runs on the CEO''s wish. He doesn''t care about labor law. Every day, there is a new policy according to the CEO''s convenience. Pay cut/ salary cut is a regular thing here. They don''t care about employees'' feelings or well-being. Salary is very low as to the market standard. The CEO promotes a toxic culture by firing people with one day''s notice, so no job security, and zero work-life balance. The CEO will call for a meeting in the middle of your off day without prior notice. You don''t have any option to say "NO".','\n',char(10)),245,68,1,2,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(249,'681c3fb0293ad62aed53424c','Assistant Manager','একদিনে চাকরি যাওয়ার জন্য বেষ্ট জায়গা। এইচ আর একজনই, জীবনেও সে অন্য কোম্পানি তে চাকরি করতে পারবে না। মালিক যা বলে তা শুনে নিজের কিছু নাই। ৩ দিনের বেশি লেইট হলে সেলারী কাটে। রিজাইন দিলে ২ মাস সেলারী দিতে চায় না, রিলিজ লেটার পাওয়ার পর মনে হবে বায়তুল মোকাররম এ মিলাদ দেই। আর না বলি।',79,101,1,0,1,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(250,'681c3fab293ad62aed534242','The best fraud company in Bangladesh','First of all it''s not a software company(though the claim). The CEO is the another hawker with sweet sweet words, CTO is a jocker who always entertain the employees. There is no policies no salary increment, even they will not give you increment which they promised to you. Basically the CEO and CTO chair is given from Metlife project, because Metlife is the main source of income of that company with a huge corruption ( Shoumen Aich, Shohel Reza and Shameem Ahmed syndicate), they will kick you off after finishing the project. You will never get an increment without an offer letter :pThey have not even chair at their office, sometimes you have to seated in a tull, there are no projects at all. Sometimes you will have to find your own job through freelauncer.com or upwork(jodio connect kenar taka tara pay kore). One day we found a rat in their office lunch box. So think thousand times before joining here. Best of luck.',1,35,1,3,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(251,'681c3e82293ad62aed53406a','Great place to work at Taghyeer Technologies',replace('Taghyeer Technologies-এ কাজ করা সত্যি বেশ ভালো অভিজ্ঞতা। অফিসেরপরিবেশ অনেক শান্ত এবং বন্ধুত্বপূর্ণ। সবাই খুব হেল্পফুল, বিশেষ করেম্যানেজমেন্ট অনেক ফ্রেন্ডলি— যেকোনো বিষয়ে কথা বলা যায় আর সবসময় সাপোর্ট করে।\nকোম্পানির পলিসি গুলোও বেশ ভালো। সবকিছু ক্লিয়ার আর ফেয়ার। সকল সরকারি ছুটি দেওয়া হয়। বিভিন্ন কম্পানিতে সরকারি ছুটি থাকা সত্ত্বেও অন্য ধর্মের ছুটিগুলো দেওয়া হয়না। বাট এখানে তেমন কোনো সমস্যা নাই।\nআর সবচেয়ে ভালো লাগে,৯টা থেকে ৬টা পর্যন্ত কাজ, মানে কাজ আর ব্যক্তিগত সময়ের মধ্যে ভালো ব্যালান্স রাখা যায়।\nসব মিলিয়ে বলা যায়, যারা রিল্যাক্সড এবং প্রফেশনাল পরিবেশে কাজ করতে চান, তাদের জন্য Taghyeer Technologies একদম পারফেক্ট।','\n',char(10)),242,40,2,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(252,'681c3dda293ad62aed533f43','প্রতারক কোম্পানি',replace('গত ৪ মাস ধরে কোনো বেতন দেয়নি।অফিসের ভেতরে চরম রাজনৈতিক খেলা ও ষড়যন্ত্র চলে।\nগ্রাহকদের সাথে প্রতারণা ও মিথ্যা প্রতিশ্রুতি দেয়।\nসবচেয়ে ভয়ঙ্কর বিষয় — ৫ই আগস্ট কোম্পানির মালিকরা দেশ ছেড়ে পালিয়ে গেছে।\nএকদমই অবিশ্বস্ত প্রতিষ্ঠান, সতর্ক থাকুন!\nএখানে কাজ করা বা কোনো সেবা নেওয়ার আগে অনেকবার ভাবুন।','\n',char(10)),160,2,1,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(253,'681c3d5d293ad62aed533e68','Good work culture in Sebpo''s Development Department',replace('Pros:\n1. Good work life balance\n2. Friendly environment','\n',char(10)),218,2,3,0,2,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(254,'681c3d22293ad62aed533e08','This company isn’t just a bad place to work — it’s a full-time nightmare. Stay away if you value your time, energy, health, and career.',replace('1. Toxic, Family-Oriented Management:The CEO, CTO, MD, COO — basically all leadership roles — are handled by one single person and their close relatives (siblings, in-laws, etc.). They behave like they own not just the company but the employees too. The environment is suffocatingly toxic, with heavy work pressure even during holidays. You’ll be expected to work from home too, without any extra compensation.\n2. Unprofessional Salary Policy:Salaries are not paid monthly as promised. Instead, payments are made in random "slabs" depending on their so-called "fund availability". Even when your salary is increased, you won''t receive the full amount. They will hold back your money indefinitely. Months will pass — you might complete a year — yet they’ll still owe you part of your rightful salary. Meanwhile, the MD is busy spending company funds for personal interests like elections, while claiming there’s no budget for employees.(400+ customers, but no money — what a joke!)\n3. Low Pay for All Levels:Beginner or senior — it doesn’t matter. Salaries are extremely low for entry-level employees and don’t improve significantly even if you stay and grow. They will always use the excuse of "no fund". If you’re senior, you’re actually at a disadvantage — they''d rather push you out and hire juniors to get the work done cheaply.\n4. No Task Management, No Process:There’s no proper task allocation or planning. You’ll just be thrown random work based on the MD’s whims. One day, you’ll be praised, the next day you might be suspended without reason. Even with full commit logs and Git history as proof, they’ll accuse you of not working.(Management style = Total Chaos.)\n5. No Employee Benefits or Job Security:Forget about bonuses, benefits, or job security. It''s a simple rule here: If you can survive, stay; if you can’t, leave. Employees are treated as replaceable resources, not as assets.\n6. Terrible Food and Hygiene:The company almost never provides good food. Maybe once or twice a year, you’ll get something like a tehari treat, but on regular days, the food quality is terrible enough to cause ulcers. No variety, no quality.(Good food? In your dreams.)\n7. No Career Growth, Fake Bosses:Employees (mostly family members) have been in the same position for 10-13 years without any growth, yet they act like they are your bosses. Promotion and development are just myths here.\n8. Extremely Poor Office Conditions:Broken ACs, faulty PCs and laptops, filthy washrooms with unbearable smells across the entire staircase and even outside on the road. The workplace is unhygienic, uncomfortable, and demotivating.','\n',char(10)),88,20,1,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(255,'681c3bd0293ad62aed533bfc','Genieinfo teach - Suitable for absolute beginners seeking an internship, but poor for long-term prospects.',replace('Pros:\nGood learning environment.\nOpportunities to experiment and practise new skills.\nCons:\nExcessive micromanagement.\nFixed start time but consistently late finishes.\nMinimal yearly increments.\nRisk of termination if questioning overtime, undue pressure, or unfair blame allocation.\nVerdict:Only stay to complete an internship—otherwise, leave as soon as possible.','\n',char(10)),117,111,3,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(256,'681c3b74293ad62aed533b60','The downfall of a good company. This company may not exist in 5-6 years.',replace('This organization, though established and reputed, appears to be struggling with outdated management practices. A notable issue is the poor condition of the company’s facilities, such as thewashrooms, which is surprising for a software company in today’s professional environment. Additionally, salary increments are significantly low—often in the range of2-5%, and in some years, there isno increaseat all. In contrast, C-level executives enjoy substantial salaries, ranging from 10 to 20 lakhs.\nThere is a lack of coordination in the company’s workflow, and while the business team often receives management’s attention and support, the engineering team—who form the backbone of the organization—does not seem to be prioritized. This disconnect between management and the engineering team may ultimately affect the company’s long-term stability.\nSenior leaders are primarily focused on meetingKPIsrather than aligning with the company’s broader strategic goals. Based on these challenges, there are concerns that the company may face difficulties in the coming years if these issues are not addressed.','\n',char(10)),212,5,3,9,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(257,'681c381d293ad62aed533603','দেশের সফটওয়্যার industry r মাফিয়া...','Ekta joghonno software tara banaia rakhche. Etai syndicate kore sell kore . Ar employee der sathe khub i baje behavoiur kore CEO ..Basis er election korche 2-3 crore khoroch kore VP hoichilo ... Pore Awame Leage jaoar pore h**ga ** mara kheye geche ..Python Team ta mutamuti valo ... Arekta ache BI team oi team er mohila arekta chele chilo ki jeno nam ... eto chilla chilli korto ... eto okottho vasa sune haste haste more jaitam amra.....IN ONE WORD ..... Bosti .... Bosti ... Bosti.... chechra',89,87,2,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(258,'681c3818293ad62aed5335fb','Highly Toxic Management, Very Bad Office Culture',replace('আমার জীবনে দেখা সবচেয়ে বাজে অফিস কালচার। স্পেশালি এইটার COO তানভির আহমেদ একজন বিগ টক্সিক পার্সন। সরকারি প্রোজেক্টের কাজে কোন অফিস টাইম নাই। পর পর ৩ দিন লেট হলে ১ দিনের সেলারি কাটা হয় অথচ দিনের পর দিন রাত ৯ টার পর বের হউয়ার পরেও এটার কোন ভ্যালু নেই। অফিস টাইম ৯-৬ টা হলেও এখানে ৯-৯ টা বেশি চলে।\nকিন্তু খারাপ ম্যানেজমেন্ট ছাড়াও আরো খারাপ দিক আছে। যারা লিড পজিশনে তারাও খুব টক্সিক! এছারা প্রোজেক্ট কো-অর্ডিনেটর, প্রোজেক্ট ম্যানেজার যারা আছেন তারা ম্যানেজমেন্টএর পা চেটে চলে আর কিভাবে সব দোষ ডেভেলপারের ঘাড়ে চাপানো যায় এই কাজে সেরা। এখানে কোন জব সিকিউরিটি নেই, ইনক্রিমেন্ট এর সময় টালবাহানা, প্রবেশন থেকে পার্মানেন্ট করার অনিচ্ছা ও বিলম্ব করা এখানে কমন সিনারিও। কাজ ভালো করেন আর নাই করেন আপনার এক্টাই কাজ COO তানভির এর চোখে ভালো থাকেন তাহলেই চাকরি থাকবে।','\n',char(10)),225,66,1,6,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(259,'681c37dd293ad62aed5335a3','Bdjobs-এর কর্পোরেট বাস্তবতা',replace('Bdjobs-এ কর্মসংস্কৃতি সংক্রান্ত কিছু গুরুত্বপূর্ণ পর্যবেক্ষণ:\nমূল্যায়নের অভাব:\nপ্রতিষ্ঠানে সঠিক মূল্যায়ন পদ্ধতির ঘাটতি রয়েছে। কর্মীদের কাজ, প্রচেষ্টা ও প্রতিভাকে যথাযথভাবে স্বীকৃতি দেওয়া হয় না।\nএইচআর বিভাগের অনুপস্থিতি:\nকোম্পানিতে আলাদা কোনো মানবসম্পদ (HR) বিভাগ নেই, ফলে সকল সিদ্ধান্তে সরাসরি CEO হস্তক্ষেপ করেন — যা পেশাদার ব্যবস্থাপনার পরিপন্থী।\nছুটি এবং কর্মঘণ্টা ব্যবস্থাপনা:\nশনিবার অফিস অল্টারনেটিভভাবে বন্ধ থাকে বলা হলেও, কোন বিশেষ দিনে (যেমন বৃহস্পতিবার বা রবিবার) অফিস থাকলে পরবর্তী শনিবার ছুটি দেওয়া হয় না। এমনকি ২৬শে মার্চের মতো জাতীয় ছুটির দিনেও কর্মীদের অফিস করতে বাধ্য করা হয়েছে।\nকর্মী সংখ্যা বনাম কর্মদক্ষতা:\nপ্রতি টিমে ১০-১৫ জন রাখা হলেও প্রকৃতপক্ষে কাজ করেন ২-৩ জন। ম্যানেজমেন্ট কোয়ালিটিকে নয়, কোয়ান্টিটিকে প্রাধান্য দেয়, ফলে দক্ষদের অবদান চোখে পড়ে না।\nপেশাগত উন্নয়ন ও গ্রোথের ঘাটতি:\nকোম্পানিতে বহু বছর কাজ করেও অনেক কর্মী প্রমোশন বা ইনক্রিমেন্ট পাননি। দীর্ঘদিন কাজ করেও কর্মীদের উন্নতির কোনো সুনির্দিষ্ট পথ বা সুযোগ নেই।\nঅযোগ্য নেতৃত্ব:\nটিম লিডারদের অনেকেই বেসিক টেকনিক্যাল জ্ঞান না রেখেই দায়িত্ব পালন করছেন। তারা কর্মীদের সঠিকভাবে মূল্যায়ন করতে অক্ষম।\nCEO-এর অপ্রাসঙ্গিক হস্তক্ষেপ:\nCEO নিজে টেকনিক্যাল ব্যাকগ্রাউন্ডের না হয়েও টেকনিক্যাল টিমের প্রতিটি আলোচনায় জড়িত হন এবং সিদ্ধান্ত দেন — যা পেশাদার দৃষ্টিকোণ থেকে অনুচিত।\nবহির্বিশ্বে একরকম, ভিতরে আরেকরকম:\nসামাজিক মাধ্যমে, বিশেষ করে LinkedIn-এ কোম্পানির শীর্ষ কর্মকর্তারা মূল্যবোধ ও ন্যায়ের কথা বলেন, অথচ বাস্তবে কর্মীদের প্রাপ্য প্রমোশন বা ছুটি অবহেলিত হয়।\nঅপ্রতুল সহায়তা ও অসৌজন্যমূলক ব্যবহার:\nAccounts বিভাগ থেকে প্রয়োজনীয় কাগজপত্র (যেমন Pay Slip, Account Statement) নিতে গেলে এমন ব্যবহার করা হয় যেন বিশাল কিছু দাবি করা হয়েছে। কর্মীদের প্রতি সহানুভূতি ও পেশাদার আচরণের অভাব রয়েছে।','\n',char(10)),30,74,1,2,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(260,'681c3728293ad62aed5334a1','Hishabee employee',replace('1. Worst place for tech guys, if they face any investment related issues thay make a major cut off on development team in every now and then\n2. When it''s time for increment or making permanent then they go for firing old one''s and hiring new employees\n( this rule is applicable only for development team)\n3. Some seniors from individual teams ( like Marketing, Product and HR),  think they are the Owner of the Company. They’re wrost for oiling, manipulate CEO''s,making syndicate''s and creating the work place toxi\n4. A Senior backend developer ruined full Development team. Though he has also fired from Shuttle, Hishabee and codemoly in a row and completed his hat-trick.\n5. No facilities for lunch, snacks, prayer, recreations\n6. Sales and customer support teams get unnecessary appreciation than entire development team. Sometimes development team meet tight deadline, tight sprint and amazing release but still unappreciated.\n7. Besides these unnecessary deadlines, uneven salary hikes, syndicates of team leaders etc are major problems.','\n',char(10)),131,13,1,1,1,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(261,'681c3709293ad62aed533476','Worst Company ever','My experience with Softlab IT has been extremely disappointing. They do not pay salaries on time, which causes a lot of financial stress for employees. The work culture is very demanding, with unrealistic expectations and long hours, often requiring work day and night without proper compensation. On top of that, the management is disorganized and unresponsive — there’s no proper structure or support system in place. I would not recommend this company to anyone looking for a stable and respectful work environment.',227,55,1,2,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(262,'681c345e293ad62aed5330f0','Bad Management','The AVP of the compnay is the worst no one chamcha but according to the MD he is the best. There is no job security one employee can be sacked any time. There is no worklife balance. Unara kono kaaj ashle proper requirement analysis and time analysis na kore start kore dei clinent der commit kore ar employee der chaap dite thake taratari sesh korar jonno sei output jotoi baje hok. Kono testing na korei production a kaaj diye then problem hoile tar daivaar employee der upore dei. Othocho tao QA nei na.Onek boro boro project kore but without tester ar vul hole tar dai vai employee der. Cost komanor jonno ekjon employee er increament na kore take baad diye new employee nei. That chamcha AVP se sob kisu te ha ha kore r baki der bitching kore MD er kase. The only good thing about the company is timely salary. Otherwise that place is toxic. One can feel suffocation there.',220,91,1,2,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(263,'681c3329293ad62aed532f8c','Bad company',replace('পুরাই স্ক্যাম কোম্পানি। জুনিয়রদের কে খাটাইয়া মারে। জামাই সিইও আর বউ জামাই এর সিইও। সাথে আছে আরেক এইচ আর কামলা সরি কামলি। ওয়াক থু ।\nজুনিয়র দের কে বলি জীবনে কোনোদিন যাইস না। লাইফে পেইন খাইয়া যাবি।','\n',char(10)),186,24,1,6,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(264,'681c32ec293ad62aed532f55','নতুনদের জন্য ভালো পরিবেশ কিন্তু অভিজ্ঞদের জন্য জাহান্নাম',replace('নেগেটিভঃ\n১। কিস্তিতে বেতন দেয়, রিজাইন করা অনেকেই এখনো টাকা পায় । কিন্তু এদিকে বিভিন্ন পোগ্রামে স্পন্সার করে বেড়ায় ।\n২। এক, দের বছর হয়ে যাওয়ার পরও সেলারী ইনক্রিমেন্ট দেয় না ।\n৩। লেবাজধারী - বাহির থেকে ফেরেশতা মনে হলেও আসলে তিনি মুলা ঝুলিয়ে রেখেছেন ।\n৪। যারা পাম পট্টী দিতে পারে তাদের গুরুত্ব অনেক এই কোম্পানিতে ।\nপজিটিভঃ\n১। কাজ এবং অফিস কালচার শিখার জন্য ভাল পরিবেশ ।\n২। প্রেশার নিয়ে কাজ করতে হয় দরুন স্কিল ভাল পরিমান ডেভেলপ হবে ।','\n',char(10)),51,11,3,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(265,'681c3011293ad62aed532cb3','Great place to work at Tech Cloud Limited','Tech Cloud Ltd is a one of the best IT companies in Bangladesh with a friendly workplace. There are no politics, so everyone feels respected. They always pay salaries on time. The management is kind and listens to employees. The office is nice and helps you work well. I really enjoy working here and recommend Tech Cloud Ltd to anyone!',243,74,2,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(266,'681c2fde293ad62aed532c7b','কাজের পরিবেশ যখন পেশাদারিত্ব হারায়',replace('স্থায়ী নিয়োগের নামে প্রতিশ্রুতি দেয়, কিন্তু প্রকল্প শেষ হতেই কর্মীদের চাকরি থেকে বাদ দেওয়া হয়।⚠️ কাজের পরিবেশ এমন যে সেখানে পেশাদারিত্বের চেয়ে রাজনীতি বেশি।\nপ্রায় প্রতিটি গুরুত্বপূর্ণ পদে এমন ব্যক্তিদের বসানো হয়েছে যাদের দক্ষতা বা যোগ্যতা সেই দায়িত্ব পালনের জন্য যথেষ্ট নয়।তারা নিজেদের পজিশন ধরে রাখতে গিয়ে চরম পর্যায়ের অভ্যন্তরীণ রাজনীতি করে এবং কর্মীদের উপর চাপিয়ে দেয় অপ্রয়োজনীয় অতিরিক্ত কর্মঘণ্টা।\n⛔ এই ধরনের পরিবেশ কর্মীদের মানসিক স্বাস্থ্য ও পেশাগত উন্নতির জন্য মারাত্মক ক্ষতিকর।','\n',char(10)),154,105,1,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(267,'681c2cb9293ad62aed532995','Frustrating Experience with Ineffective Project Manager AKM Golam Murshed',replace('I had a deeply disappointing experience working under Project Manager AKM Golam Murshed. Before the Eid-ul-Fitr holiday, he indicated me I could complete the project coding and deployment during the extended vacation period. However, he failed to show any consideration for work-life balance or basic decency. Despite the holiday, he scheduled mandatory meetings and expected everyone to work late into the night and on weekends — including during Eid.\nIronically, during regular working hours (from 12 AM to 3:30 PM), he was often unavailable or unresponsive. His project management approach is disorganized and ineffective. What’s worse, he lacks fundamental project management practices — there’s no formal documentation like BRDs or SRS; he communicates requirements verbally only. When issues inevitably arise due to unclear or missing documentation, he refuses to take responsibility and denies giving those instructions in the first place.\nHis poor communication, time-wasting meetings, and lack of accountability make working with him a draining and demoralizing experience. He frequently sets up unnecessary meetings that waste time and does little to guide or support the team. It’s extremely concerning that someone so unqualified and unprofessional is holding such a critical role within the company. His approach not only undermines the team but also damages the quality and integrity of the work. Leadership should seriously re-evaluate his position. It’s frustrating to see someone in such an important role lacking the empathy and leadership skills essential for managing people and projects. I sincerely hope the organization re-evaluates such appointments for the sake of team morale and productivity.','\n',char(10)),71,13,1,1,1,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(268,'681c2c66293ad62aed53295d','Best Boss in The World and a Great Team to Work With',replace('Alhamdulillah I am with this comany from March 2020. Started seeing this company in startup mood and we are growing day by day. You may not find everything you see in around, but I hope no one would regret after joining this company.\nFew benefits:1. Handsome salary. From joining till now, no month''s salary was due.\n2. Rations for employees.(Provided quarterly)\n3. Care for family members.\nAnd many more......\nMay Allah bless my boss and other super-supportive colleagues.','\n',char(10)),233,115,3,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(269,'681c27c4293ad62aed5325a0','Excellent Work Culture, Family Environment & Truly Supportive Team 🌟',replace('Everyone feels valued, supported, and connected. We celebrate each other’s wins and stand together during challenges—just like a real family.Our leaders lead with empathy, not ego. They guide, mentor, and listen—helping each team member grow professionally and personally.\nAt Rising Software Company, we’re not just building software—we’re building a future together. ❤️','\n',char(10)),260,67,3,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(270,'681c27bf293ad62aed53259d','Unprofessional Workplace with Poor Management and No Work-Life Balance','Poor Work-Life Balance: The company has an extremely poor work-life balance. There are no public holidays, not even on significant national days like December 16th, which is ridiculous. False Benefits & Mismanagement: They claim to provide fully subsidized coffee and tea, but it’s a scam—the coffee is terrible, and the management is disorganized. They also mention Friday lunch, but the food quality is extremely poor, likely sourced at a very cheap rate. Lack of Personal Growth: There is no opportunity for personal or professional growth since the company doesn’t have any good projects. Job Insecurity: There is no notice period—they can fire employees at any time, even telling them today that they don’t need to come in tomorrow. Unprofessional HR Policies: The HR policies lack professionalism and structure. Disrespectful Work Environment: Employees often use informal and impolite language (such as "Tui"), creating an unprofessional and disrespectful workplace. Poor Management & Decision-Making: The management is highly disorganized. For example, the CEO may request the implementation of Feature "A," but after completing half of it, the CTO may say that it is irrelevant to the project. This lack of proper planning leads to wasted time and effort.',19,40,1,4,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(271,'681c2741293ad62aed53252a','দেশি অশিক্ষিত রিপোর্টেরের মতো ক্যান্ডিডেট দের রিজেক্ট করার পর কলে জিজ্ঞেস করে, কি বাবা কেমন তোমার এক্সপেরিয়েন্স?',replace('Worst HR policy in my opinion. They reject candidates then call them to know how the experience of getting rejected was.\nI was stunned after hearing this shit over the phone. why even call a rejected candidate when you want nothing to do with him?\nThe HR acts so busy all the time time but its a shame that they failed to understand that the candidates might be busy and their time is valuable too.\nWhen you want a feedback from a rejected candidate, give a good fucking explanation in the rejection email other than a single liner vanilla bullshit. Time is valuable to everyone.You did not even spend a little time to explain why you rejected me, then call me and expect me to give you advice and share my experience? The audacity to think that i''ll spend my time talking to shitbags like you!\nUnforgettable experience. Just imagine getting a call like this.','\n',char(10)),103,18,1,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(272,'681c26a5293ad62aed5324a7','Ideal for Career Growth at HawarIT',replace('HawarIT Limited stands out as a dynamic and forward-thinking Dutch-Bangladeshi IT company, renowned for its expertise in custom software development, GIS applications, engineering drawing and modeling, photogrammetry, and LiDAR services.Since its inception in 1994, HawarIT has cultivated a reputation for delivering high-quality, cost-effective solutions to a diverse clientele, including multinational corporations and governmental organizations.\nProven Track Record:With over two decades of experience, HawarIT has successfully completed numerous projects, including more than 20 in the Netherlands and over 30 web, mobile, and online marketing initiatives.hawarit.com\nGlobal Presence with Local Expertise:Operating back offices in Bangladesh since 2000, HawarIT combines European quality assurance with the scalability and cost-efficiency of its Bangladeshi operations.\nInnovative Services:The company offers a broad spectrum of services, from software development and engineering modeling to GIS data services and photogrammetry, ensuring comprehensive solutions for complex technical needs.\nHawarIT is committed to fostering a supportive and adaptable work culture:\nEmployee-Centric Policies:Employees appreciate the company''s fixed office hours (9 AM to 6 PM), timely salary disbursements, and quality office amenities like high-quality lunches and unlimited tea and coffee.Glassdoor+1Glassdoor+1\nCollaborative Atmosphere:The management is described as approachable and receptive to feedback, contributing to a positive and collaborative workplace environment.Glassdoor\nFlexible Resource Models:HawarIT offers various resource placement models, including onsite, offsite, hybrid, and Build Your Own Team (BYOT) options, allowing for tailored collaboration that meets specific project requirements.\nFor professionals seeking to advance their careers, HawarIT provides ample opportunities for learning and development:\nDiverse Projects:Engagement in a wide array of projects across different domains ensures continuous learning and skill enhancement.hawarit.com\nSupportive Environment:The company''s culture encourages knowledge sharing and collaboration, making it an excellent place for both new graduates and experienced professionals to thrive.\nIn summary,HawarIT Limited exemplifies a harmonious blend of technical excellence, flexible work practices, and a nurturing environment, making it a standout choice for clients and professionals alike.','\n',char(10)),126,85,2,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(273,'681c2687293ad62aed532486','মানুসিক প্যারাময় কোম্পানি।','বেতন কম।ইনক্রিমেন্ট করার কথা বলে তা করে না।মানুসিক প্যারা দেয় অনেক।অতিরক্ত সময় কাজজ করায়। ( ডিউটি শেষ হলে তারপর সারাদিন কখন কি করছি রিপোর্ট দেওয়া লাগে।এগ্রিমেন্ট পেপারে স্বাক্ষর নিয়ে কর্মীদের চাপের ভিতর রাখে।',13,86,1,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(274,'681c1b4f293ad62aed531de0','Toxic Office Politics',replace('১. টক্সিক পরিবেশ।\n২. কাদা ছোঁড়াছুঁড়ি করে।\n৩. জুনিয়র সিনিয়র কে গোনাই ধরে না।\n৪. যে যত বেশি এমডি এর পা চাটতে পারবে সে তত ভালো।','\n',char(10)),114,70,1,2,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(275,'681c1b13293ad62aed531dc4','More like a school with rules and regulations, not a software company','',178,23,1,2,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(276,'681c1a1c293ad62aed531d5c','Genieinfo teach দয়া করে কোম্পানিতে কেউ কোনদিন জয়েন করবেন না','দয়া করে কোম্পানিতে কেউ কোনদিন জয়েন করবেন না,এটা ডেভলপারদের ন্যূনতম কোন দাম দেয় না,অফিস টাইম এর বাইরে সারাদিন কাজ করাবে কিন্তু সেলারি ঠিকমতো দিবে না,প্রয়োজন মিটে গেলে এরা ডেভেলপারদের দিকে চোখ ফিরেও তাকায় না আর,অফিস টাইমের বাইরে ওরা ডেভলপারদেরকে দিয়ে কুত্তার মত কাজ করায়,নিজেরা কোন ভুল করলে ক্লাইন্ট যখন ধরে সেগুলো ডেভলপারদের উপর চাপায় দেয়,চার মাসের ইন্টারনেট ৫০০০ টাকা অফার করে তারা বাট কাজ করাবে কুত্তার মত',117,35,1,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(277,'681c1956293ad62aed531ce4','প্রোজেক্ট আছে লোক আছে, প্রোজেক্ট নেই লোক নেই 🤮','এই কোম্পানি নিয়ে কি আর বলব, এদের কাজের কোন ঠিক নেই। প্রোজেক্ট আছে লোক আছে, প্রোজেক্ট নেই লোক নেই। কোম্পানির মালিক নিজে সফটওয়্যার ব্যাকগ্রাউন্ড এর কারনে কাজ ভালো হয়। কিন্তু প্রোজেক্ট না থাকার কারনে লোকজনকে লে অফ করে দেয়। কাউকে ৩ মাস, কাউকে ৪ মাস পরে বাদ দিয়ে দেয়। আরকেটা সমস্যা হল, কোন লোককে কি কারনে হায়ার করেছে মালিক নিজেও জানে না। একজন কে দিয়ে সব ধরনের কাজ করাতে চায়। পুরাতন যারা মালিক এর সাথে অনেক দিন ধরে কাজ করছে, তাদের সাথে তার খুব ভালো সম্পর্ক, বাকিরা বাদ।',74,108,1,2,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(278,'681c18fd293ad62aed531cac','উপরে ফিটফাট ভিতরে সদরঘাট',replace('* ফেইস বুক, লিংকডিন এ পোস্ট দেখে মানুষ মনে করে, এটা একটা স্বর্গরাজ্য, আহ কি সুখ।\n* জবে ঢোকার পর বুঝা যায় এরা আসলে কি পরিমান, Show Off করে, সব কিছুই করে শুধু ShowOff এর জন্যে।\n* আপনার শরীরে যদি প্রচুর তেল থাকে, ম্যানেজমেন্ট, সিনিয়র দের সেই তেল মাখতে পারেন, এবং তাদের পায়ের ধোয়া পানি খেতে পারেন তাইলে আসলেই আপনার কাছে এটা স্বর্গরাজ্য ই মনে হবে।\n* এরা একটা নিছে ২৭ তলা, সেই ২৭ তলার ভিউ এর দোহায় দিয়ে সবাইকে বলে বেড়ায় যে, বাংলাদেশের টপ কোম্পানি, আসলে ২৭ তলা ভাড়া নেওয়ার পিছনে এদের অন্য বিজনেস আছে, এরা বিভিন্ন পেইড সেমিনার করে এখানে, আর বলে বেড়ায় নাহ, আমরা তো ডেভেলপার দের জন্যে ২৭ তলা ভাড়া নিছি, ধাপ্পাবাজ।\n* এমন ও ইঞ্জিনিয়ার আছে, কাজের চাপ এত্ত দিয়ে রাখে, আপনি ২৭ তলা আছে যে, ভূলেও যাবেন, ৫ মিনিট ও সময় পাবেন না বসার।কিন্তু যারা ওই যে পা চেটে খায়, এটা দুপুরে দিব্বি লাঞ্চ এর পরে এখানে বসে আসর জমায় বিড়ি খাওয়ার, তারপর হেলেদুলে ৩/৪ টার নীচে নামবে কাজের জন্য।','\n',char(10)),265,37,3,12,3,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(279,'681c175d293ad62aed531bf4','Do you want to run in next year’s election? Then join BRAC IT today!',replace('In my entire life, I’ve never seen a circus company this big. It’s true—they pay salaries and bonuses on time, and that’s probably the only positive thing about this organization. Every layer is full of politics: within teams, between teams—constant backbiting, flattery, and credit stealing are the norm.\nAt the end of the year, you’ll be left dumbfounded trying to figure out why you didn’t get a promotion while someone else did—especially when youknowthat person didn’t do any real work.\nDo you flatter the higher-ups? Then all your sins are forgiven. Don’t flatter them? You don’t even need to make a mistake—everything will automatically be your fault.\nThey post videos and content on social media—it’s all for show, just LinkedIn marketing.\nNow you decide for yourself—if you think it’s worth it, go ahead and join.','\n',char(10)),56,27,2,5,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(280,'681c16e8293ad62aed531bc4','Very friendly and healthy startup','This is a new company genuinely aiming to make a strong impression as a Bangladeshi software development firm.',147,60,2,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(281,'681c158d293ad62aed531b30','আনপ্রফেশনাল, তেলবাজি, নারীলিপ্সুক','একেবারে উপর থেকে নিচে, একটা সিঙ্গেল পার্সনের প্রফেশনালিজম নাই। মাসের পর মাস স্যালারি দিবে নাহ, আবার জিজ্ঞেস করলে এন্সারও দিবে নাহ, এন্সার দিলেও ঝাড়ি দিবে। অনেককেই ভাল অফার দেখিয়ে এনে পরে আর স্যালারিই দিতে পারে নাহ। কিন্তু রেগুলার জব সার্কুলার দেয়, এটা নাকি তাদের কর্পোরেট রুলস। আর নারী বিষয়ে কি বলবো, এখানে একটা কথা সবাই মানে। নারী হলেই চাকরি কনফার্ম। তেলবাজদের তো কথাই নাই, এত্ত এত্ত তেলবাজ, হালকা তেল দিতে পারলে ম্যানেজমেন্ট রে তাহলেই হইছে, একদম পোয়াবারো। এছাড়া একজন সিঙ্গেল ব্যাক্তি নাই যারা যোগ্যতার বলে নিজ পদে বেশিদিন বহাল আছে। পুরা অযোগ্য অকর্মা অহংকারী লোক দিয়ে ভরা একটা প্রতিষ্ঠান।',75,21,1,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(282,'681c104a293ad62aed5319ab','Toxic management, need to beg for salary',replace('ম্যানেজমেন্ট মনে করে নো উইকেন্ড নো অফিস আয়ার লিমিট। কিন্তু বেতন দিবে ১/২ মাস পর।\nজব ছেরে দিছি প্রায় ২ বছর আমি এখনো ২ মাসের বেতন পাই।\nHR কল ধরে না। ম্যানেজমেন্ট এর কেও কল ধরে না।\nআমি এমন ৪/৫ জনকে চিনি যারা এখনো বেতন পায়নি।\nকোম্পানির মালিক সে ফ্ল্যাট কিনেছে, গাড়ি কিনেছে, গ্রামের বাড়িতে ৫ তালা building করতেছে। কিন্তু আমাদের বেতন দিচ্ছে না। তার নাকি টাকা নাই','\n',char(10)),195,66,1,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(283,'681c0d3e293ad62aed5318c1','BRACT IT: Try to Show Off but cannot. No new things','This company has no identity without brac projects. Old CEO was a thief and new CEO is a dumb head. 2 CTOs 😆 for nothing. One doing outside job another is only trying to do other departments work. Don''t be trapped into this if you are a passionate engineer. If you want comfortable, no work life; go get them right now. They are looking for jerk like you 🤣',34,106,1,5,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(284,'681c0298293ad62aed5316ef','- Think before you Join.',replace('কোম্পানির কিছু নেগেটিভ সাইড:::\n- ক্যারিয়ারের কোন গ্রোথ নেই বললেই চলে HR এ\n- গ্রীন ফ্যাক্টরি হয়ে ও স্যালারি ৭ তারিখের পরে চলে যায়।\n- শুক্রবারে ডিউটি করায়। ফোর্স লেবার। আমার সিক লিভের দিন অফিসে আসতে বলা হয়েছে।সিক লিভের দিন কেন অফিস এসে মিট করে গেলাম না,তাই সিক লিভ rejected kora hoise.\n- Eid er offday etodin hobe,bolar por seta niye talbahana kore...\n- No job Security. Not a stable job for growth. You can be fire anytime.\n- Probationer period ৬ মাস ওভার হয়ে যেতে দেখসি।','\n',char(10)),268,24,1,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(285,'681beaf5293ad62aed531292','App Develeper','দুইটা HR cum Senior developer অফিসটারে নিজেদের বাপ দাদার সম্পত্তি মনে করে। ১০-৬টা অফিস টাইম বলে জয়েনিংয়ের সময়, কোনো জীবনে ৭.৩০-৮টার আগে বের হওয়া যায় না, বের হওয়ার ঠিক ১০-১৫মিনিট আগে এমন সব কাজ দিয়ে দেয় যে বের হওয়া যায় না। স্যালারি জীবনেও মাসের ১০তারিখের মধ্যে হতে দেখি নি যতদিন আমি ছিলাম। আর যদি জব ছেড়ে দেয় কেউ তাইলে এমন ব্যবহার শুরু করে যেন তারা টাকা দিয়ে দাস কিনছে সেই দাস চলে যাচ্ছে! I wish আমি এই দুইটারে পুলিশের কাছে দিতে পারতাম এদের কৃতকর্মের জন্যে। এরা দেখতে আপাদমস্তক প্রাক্টিসিং মুসলিম হইলেও কাজের সময়ে আপনার ইমান নামাজ এক পাশে রেখে কাজ করতে হবে।',24,113,2,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(286,'681bdfd8293ad62aed531178','বাংলাদেশের সবচেয়ে জঘন্য কোম্পানি','i. ম্যানেজমেন্ট পুরাই জঘন্য এবং হিপক্রেটii. তারা যদি বুঝতে পারে , তাদের কোন ভুল হৈছে , ঐ কাজ তারা আরও বেশী  করে করবে।  যেমন সি ও ও এর একটা বাজে অভ্যাস আছে নাক খোটা , সে যদি বুঝতে পারে , আপনি বেপারটা  দেখছেন , সে আরও বেশী  করে করবে , এমন ভাবে করবে যেন  সে হাততলী চাইতেছি।   কোম্পানীতে এমন কিছু লোক  ও আছে  যদি পারতো হাত তালি  ও দিতো এই ঘটনায়, ওই চামচ গুলাই কোম্পানির সিনিয়র ইনজিনিয়ার বা ম্যানাজার  নাম পরিচিত।iii. ম্যানেজমেন্ট আর তাদের চামচা দেড় অপমান জনক কথা তো আছেই , এইগুলো এত অভদ্র মাঝে মাঝে আপনার পিছনে এসে আপনার মাথায় ও থাপ্পড় দিবেiv. খুব খেয়াল করলে দেখা যায় , এইখানে যারা লম্বা সময় ধরে আছে , তারা অন্য কোথাও বেশি দিন টিকতে পারেনা।  এই কোম্পনির মেইন কোয়ালিফিকেশন হলো ভণ্ডামি আর চামচামি',271,45,1,5,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(287,'681bdb77293ad62aed5310cd','ফাউন্ডার ওলি নিজেই রিজাইন করে চলে গেসে',replace('ওলি আহাদ নিজেকে পীর আউলিয়া গোত্রের কেউ মনে করে।\nসবাইকে তার মিষ্টি ব্যবহার দিয়ে ভুলিয়ে রাখে কিন্তু কম্পানি চালাবার বেলায় লবডংকা।\nএকটা এপয়েনমেন্ট লেটার পর্যন্ত দিবে না এত আন প্রফেশনাল এরা।\nএকমাত্র স্টেবল সোর্স অফ ইনকাম বিকাশ এর প্রজেক্ট। বিকাশ টাকা দিলে বেতন হবে আর দেরি করলে বেতন হবে না।\nবুয়েট, আই ইউ টি এবং আইবিএ ছাড়া অন্য কাউকে মানুষ মনে করে না।\nশুভদীপ নামে এক বস এর **** মুখে নিয়ে বসে থাকা জুনিয়র ছেলে আছে যার কথায় ওলি আহাদ উঠে আর বসে\nমিটিং এ বলে কম্পানির অবস্থা খারাপ, টাকা নাই কিন্তু কম্পানির টাকায় বিভিন্ন বিদেশি টেক ইভেন্টে ঘুরতে যায় ওলি আহাদ কিন্তু একটা বিজনেস ও আনতে পারে না।\nটাকার হিসাব দিতে না পারায় ইনভেস্টর দের সাথে গেঞ্জাম এবং রিজাইন করে ওলি আহাদ। কম্পানি চালাছে শুভদীপ গং রা।\nওলি আহাদ নিয়ম করেছে সে ছাড়া এমএম্পলয়ি রা কেউ আই নিয়ে কেউ সোশাল মিডিয়া তে কথা বলতে পারবে না , টিউটোরিয়াল লিখতে , ভিডিও করতে পারবে না । কারন এ আই তার বাপের সম্পত্তি','\n',char(10)),141,31,1,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(288,'681bd91b293ad62aed531098','এমডি মাসুদ নিজেকে ইলন মাস্ক মনে করে আর গালিগালাজ করে',replace('এমডি মীর মাসুদ নিজেকে ইলন মাস্ক মনে করে। প্রতিদিন এম্পলয়িদের গালি না দিলে উনার ভাত হজম হয় না। এম্পলয়িরা চাকরি ছাড়ার আগে এইচ আর, সিইও নিজেই রিজাইন দিয়ে চলে গেসে সম্মান বাচাইতে। কিছু এক্স মিলিটারি বুড়া ভাড় এনে ডাইরেক্টর বানায় রেখে দিসে।\nআসল কাস্টমার এর চেয়ে কম কাস্টমার দেখায় সরকার এর রেভেনিউ শেয়ার ফাকি দেয়ার জন্য।\nজঘন্য কাজের পরিবেশ। এরা ইনথি হোস্ট করে কিন্তু কারেন্ট চলে গেলে ডাটা সেন্টার বন্ধ হয়ে যায়। বিভিন্ন মন্ত্রী এমপি বিটিআরসির লোকজন কে নিয়মিত টাকা পাঠিয়ে হাতে রাখে এরা।\nআমি চাই না আমার শ্ত্রুও কখনো এখানে জব করুক','\n',char(10)),156,106,1,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(289,'681bd654293ad62aed531039','Unstable and uncetainity',replace('You never know when you will get fired. One day you will wake up and you will know you lost your job. And they reason will be very much typical issues " Communication lacking"\nWhen they are the who tested your communication skill through out the interview.\nAnd very bad work culture. You have to be so calles "cool"\nIf you concern about job security, do not consider this as option.','\n',char(10)),2,75,1,4,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(290,'681bc7cb293ad62aed530d62','Good working Environment and so on',replace('Everything is good.Just HR department is much slower.\nSalary structure - fine\nLunch - yes\nYearly Increment - yes\nPF - yes\nTransport - yes\nLeave policy - fine','\n',char(10)),166,11,3,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(291,'681bc797293ad62aed530d58','Excellent working environment',replace('Working atPrime Tech Solutionshas been a rewarding experience. The work environment is friendly, supportive, and collaborative, which makes day-to-day tasks enjoyable. The company embraces modern technologies, giving employees the chance to work on challenging and innovative projects across various industries.\nThere’s a strong focus on professional growth, and I’ve had opportunities to expand my skills in .NET, Python, and cloud technologies. The management is approachable and open to feedback, and they genuinely care about employee development.\nIn terms of compensation, the salary is competitive for the industry, and performance is recognized with timely appraisals and bonuses. Overall, PTSL is a great place to grow both technically and professionally.','\n',char(10)),197,91,2,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(292,'681bc301293ad62aed530c51','জঘন্য ম্যানেজমেন্ট, ক্যারিয়ারের বারোটা বাজিয়ে দিবে','এখানের ম্যানেজমেন্ট সব চেয়ে ফালতু,তারা খালি চেয়ারম্যানকে তেল দেওয়ার জন্য রেডি থাকে। এখানে অযোগ্য লোকেরা বড় পদে থাকে,আর যারা কাজ করে তাদের কিভাবে আটকাতে হয়,সেই চিন্তায় থাকে,কারন অন্য একজন কাজ করলে তো তার অসুবিধা, চেয়ারম্যান তাকে ভালো বলবে। ড্যাফোডিল করপোরেট কোন ভাইব নাই। এখানে এরা জানেই না করপোরেট মানে কি। এখানের এইচ আর জানেই না এইচ আর এর কাজ কি। আজব এক প্রতিষ্ঠান। এখানে ডুকলে আপনার ক্যারিয়ারের বারোটা বাজিয়ে দিবে। এখানের ম্যানেজমেন্ট সব জানে, তারা একাই এক একটা প্রতিষ্ঠান',84,89,2,1,1,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(293,'681bbd85293ad62aed530b03','১ কোটি ৪০ লাখ টাকা Loss followed by Cost Cutting',replace('It''s not the employees fault that the company has absolutely horrible security policy and some random troglodyte leaked a client''s private banking data in his personal GitHub repo (who was deservingly laid off with 2 months severance) but the employees are definitely suffering from it through strict cost cutting in company facilities, worse than lackluster increments, and worst of all, experienced developers getting laid off and replaced by freshers because of lower salary (But the upper management has the nerve to defend this bullcrap by saying that seniors lose their touch quickly but newly grads have a fresher mindset in work). Company used to increment like 60 to 80% for good performance but now they raise like 5k or 15k if you''re lucky.\nFresher salary may look good to you but you''re not getting much raise if you stay in this company. Also freshers are kept without work for a long time. Plenty of guys who joined this company a year ago and still haven''t joined a project. Some guy didn''t even come to the company for a whole year while getting paid and it took the management A YEAR to notice. Tells you a lot about how they manage employees. Their response to this is banning work from entirely for everyone unless you are literally dying.','\n',char(10)),95,10,1,10,1,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(294,'681bbbad293ad62aed530a20','বাইরে ফিটফাট ভিতরে কিছুটা সদরঘাট',replace('এদের বেশ কিছু ভাল দিক আছে সেগুলাই আগে বলি।\nখাবার দাবার ভালোই দেয়\nঅফিসটা অনেক সুন্দর। ডাইনিং এর জায়গাটাও বেশ ভালো। ভিউ ভালো। সাথে আছে খোলা ছাদ।\nমন চাইলে সুখটান দেয়ার ভালো জায়গা আছে অফিসের মধ্যে, ছাদেও এই সুবিধা আছে।\nস্যালারী অনটাইম। স্যালারী নিয়া কোন হাংকি পাংকি নাই।\nভালো গেমের জায়গা আছে। ঘুমানোর জায়গা ও আছে।\nমাঝে মাঝে একসাথে ভায়েরা গান ধরে। মন চাইলে টুং টাং বাজানোর যন্ত্রপাতি আছে।\nএইচ আর গুলা এমপ্লয়ী ফ্রেন্ডলি। সচরাচর কোম্পানী গুলার মত বদ এইচ আর না মোটামুটি।\nওয়ার্ক লাইফ ব্যালেন্স মোটামুটি আছে টিমের উপর ই অনেক কিছু।\nএবার আসি, সমস্যা নিয়ে।\nএখানে বেশ কিছু সেক্যুলারিজমের সমস্যা আছে। ম্যানেজমেন্টের লোক এগুলা নিয়ে এমপ্লয়ীদের সাথে ক্যাচাল ও করে। সেক্যুলার মানুষগুলা ম্যানেজমেন্ট এর খুব ধারে কাছে ঘুরতে পারে বাকিদের তুলনায়।\nকাজ কাম না কইরা আজাইরা বইসা থেকেও, অনেকে ম্যানেজমেন্ট এর প্রিয় এমপ্লয়ী হয়ে যায়। পাচাটা, তেল দিতে পারা কিছু পাব্লিক সবখানেই আছে। এখানে যেন একটু বেশীই।\nঅধিকাংশ ক্ষেত্রে একবার যদি কোন কারণে রেপুটেশান খারাপ হয়, জান দিয়া কাজ করলেও আর সেটার দাম পাওয়া যায় না।\nটিম ওয়াইজ প্রচুর ডিস্ক্রিমিনেশান আছে। কিছু কিছু টিম এর লাইফে অনেক চিল, ইভেন টিম মেম্বার দের ও। আবার কিছু কিছু টিমের অবস্থা ভালো যায় না। লাইফ হেল হইয়া যাইতে পারে।\nইদানীংকালে লে অফ কালচার শুরু করছে।\nসবচাইতে বড় সমস্যা, ম্যানেজমেন্ট এর প্রিয় পুত্রেরা ছাড়া, অন্য কেউ অনেক খাটনী করলেও সব বেকার।\nইন্টার্নাল পলিটিকস তো আছেই, এ ওরে নিয়ে, সে তারে নিয়ে, এগুলা আছেই। মজার ব্যাপার, এগুলা উপর পর্যন্ত যায়। যেটা একেবারেই উচিত না। আর উপর থেকে এইগুলা ইনভেস্টিগেট ও করে বলে মনে হয় না।\nকিছু নির্দিষ্ট কুল ডুডের সার্কেল আছে। অফিসটা এদেরই। বাকিরা কি মিটিং করে, নাকি কি করে, তাতে এদের কোন চিন্তা নাই। এরা কুল, এরা যা মন চায় করবে। এরা আবার ম্যানেজমেন্ট এর ক্লোজ।\nকিছু বয়স হওয়া অদ্ভুত সিনিয়র আছে। যাদের কাছে চাকরী মানে দাসত্ব। পাগলের মত কাজ করতে হবে। লাইফে কোন চিল করা যাবে না। এরা নিজেরাই একটা কিছু। বাকি সিনিয়র, জুনিয়ররা বানের জলে ভাইসা আসা। এদের কিছুর কথা বার্তা থেকে শুরু করে, ব্যবহার ও জঘন্য।\nকেউ কেউ সিনিয়র পর্যায়ের আছে, তাদের মতের বা কাজের সাথে না মিললে, জি বাংলার মত, ওত পাইতা থেকে গিট্টু লাগায়ে লে অফ পর্যন্ত করায়।\nস্যালারী রেনজ আর ইনক্রিমেন্ট দুইটাই যে কিসের ভিত্তিতে হয় জানা নাই। অনেক খাটনী করা, কাজ দেখানো মানুষ পায় একরকম ইনক্রিমেন্ট। আবার অনেক ফাপর পারা পাবলিক, কাম কাজ কম কইরা পেয়ে যায় আরও বেশী। খুবই পুর স্যালারী স্ট্রাকচার।\nদুই ঈদে দুই বোনাস, আর স্যালারী ছাড়া অন্য আর কোন সুবিধা নাই। মাঝে মাঝে বৈশাখ, বসন্ত, নিউ ইয়ারে পার্টি হয়।\nফাউন্ডাররা দুইজন দুইরকম, একজন অনেক ফ্রেন্ডলি, তো আরেকজন সিলেক্টিভ মানুষ ছাড়া কথাই বলে না। এমনকি তার ব্যাপারে খারাপ ব্যবহার করার, এমনকি সিনিয়র মানুষজনের সাথে বাজে ব্যবহারের এলিগেশান শুনছি।\nকিছু টিমে অনেক প্রিভিলেজ। আবার কিছু টিমের ব্যাপারে এরা একদমই বেখেয়াল।\nকিছু প্রোডাক্ট ম্যানেজার রোলের মানুষজন আছে, এরা যে নিজেদের কি ভাবে। পুরা টিমের খোজ খবর না নিয়া নিজের মত করে ম্যানেজমেন্ট এর সাথে সিদ্ধান্ত নিয়া নেয়। এটা কেমন টিম ওয়ার্ক।','\n',char(10)),266,100,1,11,3,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(295,'681bb986293ad62aed530900','Software engineer',replace('They hire freshers in bulk with salary less than their own peon.\nThe software team is lead by 2 leads who has zero knowledge on core technology. The system is running on codes older than 20 years. The product team has no product knowledge and changes things as per mood of CEO. To be noted that CEO is a respected figure in the IT industry whose main focus is now activism and being a wanna be politician.\nIts good for fresher as u can learn and break things which are already broken, they are surviving as no jobs site are available yet.\nThis business is running only for the sales team and you will question your ability as an engineer everyday.\nIdk how this product is still alive,  maybe for the blessings of unemployed youth whom they are also monetizing with pro version..\nBusiness....','\n',char(10)),47,93,2,2,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(296,'681bb6aa293ad62aed5307a8','Office politics, No Payment, Rude Behavior Cultural etc',replace('Appstick Khulna r akta IT firm , CEO Mr, Riaz. Uni onar office er senior DER pa chate r junior DER parle marte ji ... Office politics chorom....\nSalary thik moto dei nh bole client payment atke dise ... Still onker 3/4 month er salary Baki .. uni akta local private university teacher. So onkr direct student ase company te ejnno onke Mr Riaz k kisu bole nh cz Uni teacher ejnno..\nJunior theke senior er kaj koria nibe salary dibe 10k\nAt the end , se salary Mera dea public nh but taka poise nea gurai .. onar behavioral onk problem ase..','\n',char(10)),22,90,2,0,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(297,'681bb3ee293ad62aed530668','কম্পিউটার ইজ লিমিটেড: যেখানে যোগ্যতা নয়, সম্পর্কই সব',replace('কম্পিউটার ইজ লিমিটেড একটা একেবারে বাজে কোম্পানি। এখানকার ডিরেক্টররা সারাদিন ডেভেলপারদের পিছনে লেগে থাকে, যেন আর কোনো কাজ নেই। ওয়ার্ক লাইফ ব্যালেন্স বলে কিছু নেই এখানে। একটু ছুটি চাইলে বলে, "কেন নিচ্ছো? এখন নেওয়া যাবে না।" মানে, কোনো ব্যক্তিগত জীবন থাকবে না যেন\nসব ডিরেক্টর, টপ থেকে বটম—সবাই একেকজন বাজে টাইপের মানুষ। আর প্রজেক্ট ম্যানেজাররা তো ডিরেক্টরদের আত্মীয়—কাজের যোগ্যতা নাই, তবুও বড় পদের চেয়ার দখল করে বসে আছে। যারা সত্যিকারের কাজ জানে, তাদেরই এখানে ভ্যালু নাই।','\n',char(10)),78,119,1,2,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(298,'681bb366293ad62aed530619','নিয়োগ আর ছাঁটাই (Hire & Fire)',replace('১. এখানে হাতে গোনা কয়েকজন সিনিয়র স্থায়ী পদে আছে, বাকিরা সবাই অস্থায়ী। শেষ পর্যন্ত ছাঁটাই হবেই—এটা যেন নিশ্চিত।\n২. কাউকে স্থায়ী করলেও, ছয় মাসের মাথায় হঠাৎ ছাঁটাই করে দেয়।\n৩. নতুন কোনো প্রজেক্ট এলে হুট করে অনেক ইঞ্জিনিয়ার নিয়োগ দেয়। তারপর ৬-৭ মাস পর একে একে ছাঁটাই শুরু হয়। শুরুতে প্রতিদিন ১২-১৩ ঘণ্টা কাজ করাতে হয়, কিন্তু কোনো ওভারটাইমের টাকা দেয় না।\n৪. বেশি বেতনের লোভ দেখিয়ে লোক নিয়োগ দেয়, কিন্তু প্রজেক্টে নির্ভরতা কমলেই কোনো রকম আগাম জানানো ছাড়াই চাকরি থেকে বাদ দেয়। এ ধরণের আচরণ যদি প্রথম বিশ্বের কোনো দেশে হতো, তাহলে এতদিনে এদের কোম্পানির লাইসেন্সই বাতিল হয়ে যেত।\n৫. ঈদের কোনো বোনাস নেই, কাজ আর ব্যক্তিগত জীবনের কোনো ভারসাম্য নেই। কর্মীদের মানুষ হিসেবে দেখা হয় না।\nআপনি চাইলে এটি আরও সংক্ষিপ্ত বা আরও ফর্মালভাবে রূপ দিতে পারি — কী কাজে ব্যবহার করতে চান সেটা জানালে আরও নিখুঁতভাবে সাজাতে পারব।','\n',char(10)),206,44,1,2,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(299,'681bb2f8293ad62aed5305e3','Very Bad Culture  - Hire & Fire',replace('There are a few senior resources here who are permanent; the rest are all temporary. Employeesmustbe laid off eventually.\nEven after making someone permanent, they lay them off within six months.\nWhen a new project comes in, they hire a lot of engineers. Then, after 6–7 months, they gradually start laying them off. At the beginning of the project, employees have to work 12–13 hours a day, but there’s no overtime pay.\nThey lure employees with high salaries, but as soon as the project dependency decreases, they suddenly fire them. If this were a company in any first-world country, their license would be revoked.\nNo Eid bonus, no work-life balance. Employees are not treated like human beings.','\n',char(10)),206,88,1,1,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(300,'681bb2f2293ad62aed5305dd','A Deeply Dysfunctional Family-Run Company',replace('This isn’t a company—it’s a family-run disaster. Nearly every employee is a cousin, sibling, or distant relative. If you''re not part of their bloodline, you''re nothing more than disposable labor. The so-called CEO operates remotely from the UK, pretending to lead a global business merger while exploiting Bangladeshi workers who carry the entire workload without fair compensation, appreciation, or timely pay.\nSalaries are constantly delayed with recycled excuses, and raises are a fantasy unless you''re a relative or a shameless bootlicker. Promotions aren’t based on performance or skill—they’re based on who you''re related to or how well you can suck up to management.\nThe hiring process is laughable. Interviews exist only to maintain a facade. If you''re not already “in” with the family or one of their minions, you’re wasting your time. Most decisions are made behind closed doors with zero transparency or fairness.\nThe company is infested with toxic employees whose only talent is flattery. These leeches secure permanent positions while hardworking, talented staff are ignored, mistreated, or pushed out. There’s constant verbal abuse, public humiliation, and no HR accountability—because HR is just another family puppet who makes and breaks rules on a whim.\nThe company’s leadership is a complete farce. Two brothers act as co-owners, but their incompetence and lack of integrity are glaring. They preach about professionalism, but their actions reflect pure hypocrisy. They create strict policies only to break them for themselves and their favorites.\nRecently, they promoted another unqualified cousin to the role of COO. This individual lacks basic manners, education, or leadership qualities—but got the job solely through nepotism. He now walks around barking orders with no clue how to lead.\nEmployee benefits? Another joke. “Unlimited coffee” turns into monthly salary deductions if you drink more than two cups a day. Lunch? Controlled with petty rules. Time off? If you’re family, you get it without question. If not, good luck getting approved.\nIf a relative leaves and goes abroad, they can return months later and be reinstated immediately. But for others :D.\nThis company thrives on favoritism, manipulation, and exploitation. There is no vision, no ethics, and certainly no future. It’s a textbook example of how mixing business with nepotism creates a hellish, demoralizing, and utterly dysfunctional environment. A place where talent dies, and mediocrity is promoted—loudly and proudly.','\n',char(10)),269,89,1,4,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(301,'681bb064293ad62aed53044a','Fascist company','',92,46,1,4,0,'2026-05-20 13:12:17');
INSERT INTO reviews VALUES(302,'681baae8293ad62aed5300e2','Worst company',replace('There management is one the worst management. And they think engineer as a garments worker.\nSpecially there previous HR shafin. ( kh shafin).\nHe managed the employee as like slave.','\n',char(10)),236,94,2,0,0,'2026-05-20 13:12:17');
